import { BaseRepository } from './BaseRepository.js';
import { databaseManager } from './DatabaseManager.js';

/**
 * Convert a boolean value to SQLite integer (1/0) or null.
 * @param {boolean|null|undefined} value
 * @param {number|null} [defaultValue] - Default value if undefined
 * @returns {number|null}
 */
function boolToSqlite(value, defaultValue = null) {
  if (value === undefined) return defaultValue;
  if (value === null) return null;
  return value ? 1 : 0;
}

/**
 * Prepare lane insert values from data object.
 * @param {Object} data - Lane data
 * @returns {Array} Array of values for INSERT
 */
function prepareLaneValues(data) {
  return [
    data.onEnterTemplateId || null,
    data.onEnterPrompt || null,
    data.onEnterMode || null,
    data.onEnterModel || null,
    data.onEnterEffortLevel || null,
    boolToSqlite(data.onEnterThinkingEnabled),
    data.onEnterAutoRescheduleEnabled ? 1 : 0,
    data.onEnterRescheduleDelayMinutes ?? 15,
    boolToSqlite(data.onEnterRescheduleOnTokenLimit, 1),
    boolToSqlite(data.onEnterRescheduleOnServiceError, 1),
    data.onEnterMaxRescheduleCount ?? null,
    data.onEnterMaxTotalTokens ?? null,
    data.onEnterRescheduleAtTokenCount ?? null,
  ];
}

/**
 * Kanban lane repository class
 */
export class KanbanLaneRepository extends BaseRepository {
  constructor() {
    super('kanban_lanes', KanbanLaneRepository.#mapLane);
  }

  static #mapLane(row) {
    return {
      id: row.id,
      boardId: row.board_id,
      name: row.name,
      sortOrder: row.sort_order,
      onEnterTemplateId: row.on_enter_template_id,
      onEnterPrompt: row.on_enter_prompt,
      onEnterMode: row.on_enter_mode,
      onEnterModel: row.on_enter_model,
      onEnterEffortLevel: row.on_enter_effort_level,
      onEnterThinkingEnabled: row.on_enter_thinking_enabled === null ? null : Boolean(row.on_enter_thinking_enabled),
      onEnterAutoRescheduleEnabled: Boolean(row.on_enter_auto_reschedule_enabled),
      onEnterRescheduleDelayMinutes: row.on_enter_reschedule_delay_minutes,
      onEnterRescheduleOnTokenLimit: row.on_enter_reschedule_on_token_limit === null ? null : Boolean(row.on_enter_reschedule_on_token_limit),
      onEnterRescheduleOnServiceError: row.on_enter_reschedule_on_service_error === null ? null : Boolean(row.on_enter_reschedule_on_service_error),
      onEnterMaxRescheduleCount: row.on_enter_max_reschedule_count,
      onEnterMaxTotalTokens: row.on_enter_max_total_tokens,
      onEnterRescheduleAtTokenCount: row.on_enter_reschedule_at_token_count,
      createdAt: row.created_at,
      updatedAt: row.updated_at,
    };
  }

  /**
   * Get all lanes for a board, ordered by sort_order
   * @param {string} boardId
   * @returns {Array}
   */
  getByBoardId(boardId) {
    const rows = this.db
      .prepare('SELECT * FROM kanban_lanes WHERE board_id = ? ORDER BY sort_order')
      .all(boardId);
    return this.mapAll(rows);
  }

  /**
   * Create a new lane
   * @param {string} boardId
   * @param {Object} data
   * @param {string} data.name
   * @param {number} [data.sortOrder]
   * @param {string|null} [data.onEnterTemplateId]
   * @param {string|null} [data.onEnterPrompt]
   * @returns {Object}
   */
  create(boardId, data) {
    const id = databaseManager.generateId();
    const now = Date.now();
    const sortOrder = this.#resolveSortOrder(boardId, data.sortOrder);
    const laneValues = prepareLaneValues(data);

    this.db
      .prepare(
        `INSERT INTO kanban_lanes (
          id, board_id, name, sort_order, on_enter_template_id, on_enter_prompt,
          on_enter_mode, on_enter_model, on_enter_effort_level, on_enter_thinking_enabled,
          on_enter_auto_reschedule_enabled, on_enter_reschedule_delay_minutes,
          on_enter_reschedule_on_token_limit, on_enter_reschedule_on_service_error,
          on_enter_max_reschedule_count, on_enter_max_total_tokens,
          on_enter_reschedule_at_token_count,
          created_at, updated_at
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`
      )
      .run(id, boardId, data.name, sortOrder, ...laneValues, now, now);

    return this.getById(id);
  }

  /**
   * Resolve sort order, defaulting to end of list if not provided.
   * @param {string} boardId
   * @param {number|undefined|null} sortOrder
   * @returns {number}
   */
  #resolveSortOrder(boardId, sortOrder) {
    if (sortOrder !== undefined && sortOrder !== null) {
      return sortOrder;
    }
    const maxRow = this.db
      .prepare('SELECT MAX(sort_order) as max_order FROM kanban_lanes WHERE board_id = ?')
      .get(boardId);
    return (maxRow?.max_order ?? -1) + 1;
  }

  /**
   * Update a lane
   * @param {string} id
   * @param {Object} data
   * @param {string} [data.name]
   * @param {number} [data.sortOrder]
   * @param {string|null} [data.onEnterTemplateId]
   * @param {string|null} [data.onEnterPrompt]
   * @returns {Object}
   */
  update(id, data) {
    // Field mapping: camelCase -> snake_case
    const fieldMap = {
      name: 'name',
      sortOrder: 'sort_order',
      onEnterTemplateId: 'on_enter_template_id',
      onEnterPrompt: 'on_enter_prompt',
      onEnterMode: 'on_enter_mode',
      onEnterModel: 'on_enter_model',
      onEnterEffortLevel: 'on_enter_effort_level',
      onEnterThinkingEnabled: 'on_enter_thinking_enabled',
      onEnterAutoRescheduleEnabled: 'on_enter_auto_reschedule_enabled',
      onEnterRescheduleDelayMinutes: 'on_enter_reschedule_delay_minutes',
      onEnterRescheduleOnTokenLimit: 'on_enter_reschedule_on_token_limit',
      onEnterRescheduleOnServiceError: 'on_enter_reschedule_on_service_error',
      onEnterMaxRescheduleCount: 'on_enter_max_reschedule_count',
      onEnterMaxTotalTokens: 'on_enter_max_total_tokens',
      onEnterRescheduleAtTokenCount: 'on_enter_reschedule_at_token_count',
    };

    const updates = [];
    const values = [];

    // Build update clauses dynamically
    for (const [camelKey, snakeKey] of Object.entries(fieldMap)) {
      if (data[camelKey] !== undefined) {
        updates.push(`${snakeKey} = ?`);

        // Handle boolean conversions for specific fields
        if (camelKey === 'onEnterThinkingEnabled') {
          values.push(data[camelKey] === null ? null : (data[camelKey] ? 1 : 0));
        } else if (camelKey === 'onEnterAutoRescheduleEnabled' ||
                   camelKey === 'onEnterRescheduleOnTokenLimit' ||
                   camelKey === 'onEnterRescheduleOnServiceError') {
          values.push(data[camelKey] ? 1 : 0);
        } else {
          values.push(data[camelKey]);
        }
      }
    }

    if (updates.length === 0) return this.getById(id);

    updates.push('updated_at = ?');
    values.push(Date.now());
    values.push(id);

    this.db.prepare(`UPDATE kanban_lanes SET ${updates.join(', ')} WHERE id = ?`).run(...values);

    return this.getById(id);
  }

  /**
   * Reorder lanes based on an array of lane IDs
   * @param {string} boardId
   * @param {string[]} laneIds - Ordered array of lane IDs
   */
  reorder(boardId, laneIds) {
    const now = Date.now();

    databaseManager.transaction(() => {
      const updateStmt = this.db.prepare(
        'UPDATE kanban_lanes SET sort_order = ?, updated_at = ? WHERE id = ? AND board_id = ?'
      );

      laneIds.forEach((laneId, index) => {
        updateStmt.run(index, now, laneId, boardId);
      });
    });
  }

  /**
   * Get a single lane with its board info
   * @param {string} id
   * @returns {Object|null}
   */
  getById(id) {
    const row = this.db.prepare('SELECT * FROM kanban_lanes WHERE id = ?').get(id);
    return this.map(row);
  }

  /**
   * Get lane by ID with template info (for on-enter triggers)
   * @param {string} id
   * @returns {Object|null}
   */
  getByIdWithTemplate(id) {
    const row = this.db
      .prepare(
        `SELECT kl.*, st.name as template_name, st.prompt as template_prompt
         FROM kanban_lanes kl
         LEFT JOIN session_templates st ON kl.on_enter_template_id = st.id
         WHERE kl.id = ?`
      )
      .get(id);

    if (!row) return null;

    const mappedLane = this.map(row);
    return {
      ...mappedLane,
      template: row.template_name
        ? {
            id: row.on_enter_template_id,
            name: row.template_name,
            prompt: row.template_prompt,
          }
        : null,
    };
  }

  /**
   * Delete a lane
   * @param {string} id
   */
  delete(id) {
    super.delete(id);
  }
}

import { BaseRepository } from './BaseRepository.js';
import { databaseManager } from './DatabaseManager.js';

/**
 * Session template repository class
 */
export class SessionTemplateRepository extends BaseRepository {
  constructor() {
    super('session_templates', SessionTemplateRepository.#mapTemplate);
  }

  static #mapTemplate(row) {
    return {
      id: row.id,
      projectId: row.project_id,
      name: row.name,
      prompt: row.prompt,
      nextTemplateId: row.next_template_id,
      thinkingEnabled: row.thinking_enabled === null ? null : Boolean(row.thinking_enabled),
      gitBranch: row.git_branch,
      gitMode: row.git_mode,
      model: row.model || null,
      mode: row.mode || null,
      effortLevel: row.effort_level ?? null,
      targetLaneId: row.target_lane_id || null,
      createdAt: row.created_at,
      updatedAt: row.updated_at,
    };
  }

  /**
   * Create a new session template
   * @param {Object} data
   * @param {string|null} data.projectId - null for global templates
   * @param {string} data.name
   * @param {string} data.prompt
   * @param {string|null} data.nextTemplateId
   * @param {boolean|null} data.thinkingEnabled
   * @param {string|null} data.gitBranch
   * @param {string|null} data.gitMode
   * @param {string|null} data.model
   * @param {string|null} data.mode
   * @param {string|null} data.effortLevel
   * @returns {Object}
   */
  create(data) {
    const id = databaseManager.generateId();
    const now = Date.now();
    this.db
      .prepare(
        `INSERT INTO session_templates (id, project_id, name, prompt, next_template_id, thinking_enabled, git_branch, git_mode, model, mode, effort_level, target_lane_id, created_at, updated_at)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`
      )
      .run(
        id,
        data.projectId || null,
        data.name,
        data.prompt,
        data.nextTemplateId || null,
        data.thinkingEnabled === null || data.thinkingEnabled === undefined ? null : (data.thinkingEnabled ? 1 : 0),
        data.gitBranch || null,
        data.gitMode || null,
        data.model || null,
        data.mode !== undefined && data.mode !== null ? data.mode : null,
        data.effortLevel ?? null,
        data.targetLaneId || null,
        now,
        now
      );
    return this.getById(id);
  }

  /**
   * Update a session template
   * @param {string} id
   * @param {Object} data
   * @returns {Object}
   */
  update(id, data) {
    const updates = [];
    const values = [];

    if (data.name !== undefined) {
      updates.push('name = ?');
      values.push(data.name);
    }
    if (data.prompt !== undefined) {
      updates.push('prompt = ?');
      values.push(data.prompt);
    }
    if (data.nextTemplateId !== undefined) {
      updates.push('next_template_id = ?');
      values.push(data.nextTemplateId);
    }
    if (data.thinkingEnabled !== undefined) {
      updates.push('thinking_enabled = ?');
      values.push(data.thinkingEnabled === null ? null : (data.thinkingEnabled ? 1 : 0));
    }
    if (data.gitBranch !== undefined) {
      updates.push('git_branch = ?');
      values.push(data.gitBranch || null);  // Match create() behavior: empty string -> null
    }
    if (data.gitMode !== undefined) {
      updates.push('git_mode = ?');
      values.push(data.gitMode);
    }
    if (data.model !== undefined) {
      updates.push('model = ?');
      values.push(data.model);
    }
    if (data.mode !== undefined) {
      updates.push('mode = ?');
      values.push(data.mode);
    }
    if (data.effortLevel !== undefined) {
      updates.push('effort_level = ?');
      values.push(data.effortLevel);
    }
    if (data.targetLaneId !== undefined) {
      updates.push('target_lane_id = ?');
      values.push(data.targetLaneId);
    }

    if (updates.length === 0) return this.getById(id);

    updates.push('updated_at = ?');
    values.push(Date.now());
    values.push(id);

    this.db.prepare(`UPDATE session_templates SET ${updates.join(', ')} WHERE id = ?`).run(...values);

    return this.getById(id);
  }

  /**
   * Get all global templates (projectId is null)
   * @returns {Array}
   */
  getGlobal() {
    const rows = this.db
      .prepare('SELECT * FROM session_templates WHERE project_id IS NULL ORDER BY name')
      .all();
    return this.mapAll(rows);
  }

  /**
   * Get templates by project ID
   * @param {string} projectId
   * @returns {Array}
   */
  getByProjectId(projectId) {
    const rows = this.db
      .prepare('SELECT * FROM session_templates WHERE project_id = ? ORDER BY name')
      .all(projectId);
    return this.mapAll(rows);
  }

  /**
   * Get all templates available for a project (project-specific + global)
   * @param {string} projectId
   * @returns {Object} { project: Array, global: Array }
   */
  getAvailableForProject(projectId) {
    return {
      project: this.getByProjectId(projectId),
      global: this.getGlobal(),
    };
  }

  /**
   * Get all templates
   * @returns {Array}
   */
  getAll() {
    const rows = this.db
      .prepare('SELECT * FROM session_templates ORDER BY project_id NULLS FIRST, name')
      .all();
    return this.mapAll(rows);
  }
}

/**
 * Migrations for the conversations, conversation_messages, and message_attachments tables.
 * Each export is an array of { name, up(db) } migration objects.
 */
import crypto from 'crypto';
import { addColumnIfMissing, getColumns } from './migrationUtils.js';

/**
 * Create default conversations for existing sessions that don't have any
 * and associate orphaned messages with the default conversation.
 */
function migrateExistingSessionsToConversations(db) {
  const sessionsWithoutConversations = db
    .prepare(
      `
      SELECT DISTINCT s.id FROM sessions s
      LEFT JOIN conversations c ON c.session_id = s.id
      WHERE c.id IS NULL
      AND EXISTS (SELECT 1 FROM conversation_messages m WHERE m.session_id = s.id)
    `
    )
    .all();

  for (const session of sessionsWithoutConversations) {
    const convId = crypto.randomUUID();
    const now = Date.now();

    db.prepare(
      `INSERT INTO conversations (id, session_id, name, is_active, created_at, updated_at)
       VALUES (?, ?, ?, 1, ?, ?)`
    ).run(convId, session.id, 'Initial', now, now);

    db.prepare(
      `UPDATE conversation_messages SET conversation_id = ? WHERE session_id = ? AND conversation_id IS NULL`
    ).run(convId, session.id);
  }
}

