import { spawn } from 'child_process';
import { platform } from 'os';
import { commandRuns } from '../database.js';
import { createRobustEnv } from './nodeSpawnHelper.js';

/**
 * Strip ANSI escape codes from text
 * Removes all CSI (Control Sequence Introducer) sequences:
 * - SGR codes: \x1b[...m (colors, bold, italic, etc.)
 * - Cursor movement: \x1b[1A, \x1b[2B, etc.
 * - Line/screen clearing: \x1b[2K, \x1b[0J, etc.
 * - Other CSI sequences: \x1b[...H, \x1b[...J, etc.
 *
 * @param {string} text - Text potentially containing ANSI codes
 * @returns {string} Text with all ANSI codes removed
 */
export function stripAnsiCodes(text) {
  if (!text || typeof text !== 'string') {
    return text;
  }
  // Match all CSI sequences: ESC [ <params> <final-char>
  // This covers colors, cursor movement, line clearing, and other terminal control sequences
  // eslint-disable-next-line no-control-regex
  return text.replace(/\x1b\[[0-9;?]*[A-Za-z]/g, '');
}

/**
 * Terminal output processor that simulates cursor control behavior
 *
 * When tools like yarn run in TTY mode, they use cursor control sequences to create
 * animated progress displays. For example:
 *   \x1b[2K\x1b[1G[] 0/576    <- clear line, go to column 1, print progress
 *   \x1b[2K\x1b[1G[] 136/576  <- clear line, go to column 1, print NEW progress
 *
 * On a real terminal, the second line overwrites the first. But when we just strip
 * the codes, we get "[] 0/576[] 136/576" concatenated together.
 *
 * This processor simulates the terminal behavior by:
 * 1. Maintaining a "current line" buffer (content since last newline)
 * 2. When we see \x1b[2K (clear line), we clear the current line buffer
 * 3. When we see \x1b[1G (cursor to column 1), we clear the current line buffer
 * 4. When we see \r (carriage return), we clear the current line buffer
 * 5. When we see \n, we flush the current line and start fresh
 * 6. All ANSI escape codes are stripped from output
 */
export class TerminalOutputProcessor {
  constructor() {
    /** @type {string} Content on the current line (since last newline) */
    this.currentLine = '';
  }

  /**
   * Handle a CSI (Control Sequence Introducer) command
   * Returns true if the current line should be cleared
   * @param {string} cmd - The command character
   * @param {string} params - The parameters string
   * @returns {boolean} Whether to clear the current line
   */
  #shouldClearLineForCSI(cmd, params) {
    // Erase in Line: [0K = to end, [1K = to start, [2K = entire line
    if (cmd === 'K') return true;
    // Cursor Character Absolute: [1G = go to column 1 (start of line)
    if (cmd === 'G' && (params === '' || params === '1')) return true;
    // Cursor Position: [n;mH or [n;mf moves cursor to row n, column m
    if (cmd === 'H' || cmd === 'f') return true;
    // Cursor movement: A=up, B=down, C=right, D=left
    if (cmd === 'A' || cmd === 'B' || cmd === 'C' || cmd === 'D') return true;
    // Erase in Display: [0J = to end, [1J = to start, [2J = entire screen
    if (cmd === 'J') return true;
    return false;
  }

  /**
   * Process a chunk of terminal output, simulating cursor control behavior
   *
   * @param {string} chunk - Raw terminal output chunk
   * @returns {string} Processed output with cursor behavior simulated and ANSI codes stripped
   */
  process(chunk) {
    if (!chunk || typeof chunk !== 'string') {
      return '';
    }

    let output = '';
    let i = 0;

    while (i < chunk.length) {
      // Check for ESC sequence
      if (chunk[i] === '\x1b' && chunk[i + 1] === '[') {
        // Parse the CSI sequence: ESC [ <params> <command>
        let j = i + 2;
        while (j < chunk.length && /[0-9;?]/.test(chunk[j])) {
          j++;
        }

        if (j < chunk.length) {
          const cmd = chunk[j];
          const params = chunk.slice(i + 2, j);

          // Handle cursor control sequences that affect line content
          if (this.#shouldClearLineForCSI(cmd, params)) {
            this.currentLine = '';
          }
          // All other sequences (including color codes 'm') are just stripped

          i = j + 1;
          continue;
        }
      }

      // Handle carriage return - go to start of line (used for overwriting)
      if (chunk[i] === '\r') {
        // Don't clear if next char is \n (normal line ending)
        if (chunk[i + 1] !== '\n') {
          this.currentLine = '';
        }
        i++;
        continue;
      }

      // Handle newline - flush current line and start fresh
      if (chunk[i] === '\n') {
        output += `${this.currentLine  }\n`;
        this.currentLine = '';
        i++;
        continue;
      }

      // Regular character - add to current line
      this.currentLine += chunk[i];
      i++;
    }

    return output;
  }

  /**
   * Flush any remaining content in the current line buffer
   * Call this when the stream ends to get the final incomplete line
   *
   * @returns {string} Any remaining content
   */
  flush() {
    const remaining = this.currentLine;
    this.currentLine = '';
    return remaining;
  }

  /**
   * Reset the processor state
   */
  reset() {
    this.currentLine = '';
  }
}

/**
 * Service for running commands and managing their execution
 */
export class CommandRunner {
  constructor() {
    this.processes = new Map(); // runId -> { process, timeout, outputBuffer, lastDbWrite }
    this.outputBufferFlushInterval = 500; // Flush buffered output every 500ms
  }

  /**
   * Create database record for a command run.
   */
  #createDatabaseRecord(runId, sessionId, buttonId) {
    if (!commandRuns || typeof commandRuns.create !== 'function') return;
    try {
      commandRuns.create({ id: runId, sessionId, buttonId });
      console.log(`[commandRunner.run] Created run record in database for runId: ${runId}`);
    } catch (dbErr) {
      console.warn(`[commandRunner.run] Warning: Failed to create database record for runId: ${runId}`, dbErr.message);
    }
  }

  /**
   * Wrap command with platform-specific TTY allocation.
   */
  #wrapCommandForPlatform(command) {
    const osType = platform();
    if (osType === 'linux') {
      return `script -q -e -c ${JSON.stringify(command)} /dev/null`;
    }
    return `script -q /dev/null sh -c ${JSON.stringify(command)}`;
  }

  /**
   * Create process entry with buffer management.
   */
  #createProcessEntry(child, sessionId, buttonId) {
    return {
      process: child,
      startTime: Date.now(),
      sessionId,
      buttonId,
      output: '',
      outputBuffer: '',
      lastDbWrite: Date.now(),
      bufferFlushTimer: null,
      outputProcessor: new TerminalOutputProcessor(),
    };
  }

  /**
   * Flush buffered output to database.
   */
  #flushOutputBuffer(entryInput, runId) {
    const entry = entryInput;
    if (!entry.outputBuffer) return;
    if (!entry.sessionId || !entry.buttonId) return;
    if (!commandRuns || typeof commandRuns.appendOutput !== 'function') return;
    try {
      commandRuns.appendOutput(runId, entry.outputBuffer);
      entry.lastDbWrite = Date.now();
    } catch (err) {
      console.warn(`[commandRunner.run] Warning: Error flushing output to database for runId: ${runId}`, err.message);
    }
    entry.outputBuffer = '';
  }

  /**
   * Handle process close event.
   * @param {{ entry: object, runId: string, exitCode: number|null, signal: string|null }} ctx
   * @param {function|undefined} onComplete - Completion callback
   */
  #handleProcessClose(ctx, onComplete) {
    const { entry, runId, exitCode, signal } = ctx;
    const remainingText = entry.outputProcessor.flush();
    if (remainingText) {
      entry.output += remainingText;
      entry.outputBuffer += remainingText;
    }
    this.#flushOutputBuffer(entry, runId);
    console.log(`[commandRunner.run] Process closed for runId: ${runId}, exitCode: ${exitCode}, signal: ${signal}`);

    if (commandRuns && typeof commandRuns.complete === 'function' && typeof commandRuns.markKilled === 'function') {
      try {
        if (signal) {
          commandRuns.markKilled(runId, entry.output);
        } else {
          commandRuns.complete(runId, exitCode || 0, entry.output);
        }
        console.log(`[commandRunner.run] Marked run as complete in database for runId: ${runId}`);
      } catch (dbErr) {
        console.warn(`[commandRunner.run] Warning: Error marking run as complete in database for runId: ${runId}`, dbErr.message);
      }
    }

    this.processes.delete(runId);
    if (onComplete) onComplete(exitCode, entry.output);
    // Use ?? 1 (not signal-specific codes like 143 for SIGTERM) because:
    // - Exit codes >128 indicate signal termination (convention: 128 + signal number)
    // - Normalizing to 1 simplifies error handling for consumers
    // - The signal information is already logged above for debugging
    return exitCode ?? 1;
  }

  /**
   * Run a command and stream output via callback
   *
   * @param {{ runId: string, command: string, workingDirectory: string }} params - Command parameters
   * @param {{ onOutput?: function, onComplete?: function, onError?: function }} callbacks - Callback functions
   * @param {{ sessionId?: string, buttonId?: string }} metadata - Optional metadata
   * @returns {Promise<number>} Exit code
   */
  async run(params, callbacks = {}, metadata = {}) {
    const { runId, command, workingDirectory } = params;
    const { onOutput, onComplete, onError } = callbacks;
    const { sessionId, buttonId } = metadata;

    return new Promise((resolve) => {
      try {
        this.#createDatabaseRecord(runId, sessionId, buttonId);
        const wrappedCommand = this.#wrapCommandForPlatform(command);

        const child = spawn('sh', ['-c', wrappedCommand], {
          cwd: workingDirectory,
          stdio: ['pipe', 'pipe', 'pipe'],
          detached: true,
          env: createRobustEnv(),
        });

        const entry = this.#createProcessEntry(child, sessionId, buttonId);
        this.processes.set(runId, entry);

        // Buffer timer management
        const clearBufferTimer = () => {
          if (entry.bufferFlushTimer) {
            clearInterval(entry.bufferFlushTimer);
            entry.bufferFlushTimer = null;
          }
        };
        entry.bufferFlushTimer = setInterval(() => this.#flushOutputBuffer(entry, runId), this.outputBufferFlushInterval);

        // Data handler for both stdout and stderr
        const handleData = (data) => {
          const text = entry.outputProcessor.process(data.toString());
          if (text) {
            entry.output += text;
            entry.outputBuffer += text;
            if (onOutput) onOutput(text);
          }
        };

        child.stdout.on('data', handleData);
        child.stderr.on('data', handleData);

        child.on('error', (err) => {
          clearBufferTimer();
          const remainingText = entry.outputProcessor.flush();
          if (remainingText) {
            entry.output += remainingText;
            entry.outputBuffer += remainingText;
          }
          this.#flushOutputBuffer(entry, runId);
          const msg = `Failed to execute command: ${err.message}`;
          console.error(`[commandRunner.run] Error for runId: ${runId}`, err);
          if (onError) onError(msg);
          if (commandRuns && typeof commandRuns.complete === 'function') {
            try { commandRuns.complete(runId, 1, entry.output); } catch (dbErr) { console.warn('[commandRunner.run] Warning: Error completing run in database for runId:', runId, dbErr.message); }
          }
          this.processes.delete(runId);
          resolve(1);
        });

        child.on('close', (exitCode, signal) => {
          clearBufferTimer();
          const remainingText = entry.outputProcessor.flush();
          if (remainingText) {
            entry.output += remainingText;
            entry.outputBuffer += remainingText;
            if (onOutput) onOutput(remainingText);
          }
          resolve(this.#handleProcessClose({ entry, runId, exitCode, signal }, onComplete));
        });
      } catch (err) {
        const msg = `Error running command: ${err.message}`;
        console.error(`[commandRunner.run] Exception for runId: ${runId}`, err);
        if (onError) onError(msg);
        // Mark as error in database (if available) and persist the error message
        if (commandRuns && typeof commandRuns.complete === 'function') {
          try {
            commandRuns.complete(runId, 1, `[Error] ${msg}`);
          } catch (dbErr) {
            console.warn(`[commandRunner.run] Warning: Error marking failed run in database for runId: ${runId}`, dbErr.message);
          }
        }
        this.processes.delete(runId);
        resolve(1);
      }
    });
  }

  /**
   * Kill a running process
   * @param {string} runId
   * @returns {boolean} True if process was killed, false if not found
   */
  kill(runId) {
    const entry = this.processes.get(runId);
    if (!entry) {
      console.log(`[commandRunner.kill] Process not found for runId: ${runId}`);
      return false;
    }

    try {
      const pid = entry.process.pid;
      console.log(`[commandRunner.kill] Sending SIGTERM to process group for runId: ${runId}, pid: ${pid}`);

      // Kill the entire process group (negative PID) to ensure child processes are also killed
      try {
        process.kill(-pid, 'SIGTERM');
      } catch (e) {
        // Fallback to killing just the process if process group kill fails
        console.log(`[commandRunner.kill] Process group kill failed, killing single process: ${e.message}`);
        entry.process.kill('SIGTERM');
      }

      // Give it a moment to terminate gracefully, then force kill
      setTimeout(() => {
        // Check if process is still in our map (not yet closed)
        if (this.processes.has(runId)) {
          console.log(`[commandRunner.kill] Process still running, sending SIGKILL to runId: ${runId}`);
          try {
            process.kill(-pid, 'SIGKILL');
          } catch (e) {
            // Fallback to killing just the process if process group kill fails
            try {
              entry.process.kill('SIGKILL');
            } catch (err) {
              // Process may have already exited
              console.log(`[commandRunner.kill] SIGKILL failed, process may have exited: ${err.message}`);
            }
          }
        } else {
          console.log(`[commandRunner.kill] Process already exited for runId: ${runId}`);
        }
      }, 1000);

      // Flush any remaining output (database mark as killed will be done in close event)
      if (entry.bufferFlushTimer) {
        clearInterval(entry.bufferFlushTimer);
        entry.bufferFlushTimer = null;
      }
      if (entry.outputBuffer && commandRuns && typeof commandRuns.appendOutput === 'function') {
        try {
          commandRuns.appendOutput(runId, entry.outputBuffer);
          entry.outputBuffer = '';
        } catch (err) {
          console.warn(
            `[commandRunner.kill] Warning: Error flushing output to database for runId: ${runId}`,
            err.message
          );
        }
      }
      // Note: We don't mark as killed here because the close event will handle it
      // This is to avoid race conditions where we mark it killed before the process actually closes

      return true;
    } catch (err) {
      console.error(`Error killing process ${runId}:`, err);
      return false;
    }
  }

  /**
   * Get all active runs
   * @returns {Map} Map of runId -> process info
   */
  getActiveRuns() {
    return new Map(this.processes);
  }

  /**
   * Check if a run is active
   * @param {string} runId
   * @returns {boolean}
   */
  isRunning(runId) {
    return this.processes.has(runId);
  }

  /**
   * Get all running commands for a project
   * Used for merging in-memory running commands with completed runs from the database
   * @param {string} projectId
   * @param {Function} getSessionById - Function to look up session by ID
   * @returns {Array} Running command runs
   */
  getRunningByProjectId(projectId, getSessionById) {
    const results = [];
    for (const [runId, entry] of this.processes.entries()) {
      // Look up session to check projectId
      const session = getSessionById(entry.sessionId);
      if (session?.projectId === projectId) {
        results.push({
          id: runId,
          runId,
          buttonId: entry.buttonId,
          sessionId: entry.sessionId,
          status: 'running',
          output: entry.output,
          exitCode: null,
          startedAt: entry.startTime,
        });
      }
    }
    return results;
  }

  /**
   * Get all active runs for a specific session (both running and recent completed)
   * @param {string} sessionId
   * @returns {Array} Array of run info objects
   */
  /**
   * Mark an orphaned run as error in the database
   * @param {Object} dbRun - The database run record
   */
  #markOrphanedRunAsError(dbRun) {
    console.log(
      `[commandRunner.getRunsBySession] Orphaned run detected: ${dbRun.id}, marking as error`
    );
    if (typeof commandRuns.complete === 'function') {
      try {
        commandRuns.complete(dbRun.id, -1, dbRun.output || '');
      } catch (updateErr) {
        console.warn(
          `[commandRunner.getRunsBySession] Failed to update orphaned run: ${updateErr.message}`
        );
      }
    }
  }

  /**
   * Process a database run record and return a normalized run object
   * @param {Object} dbRun - The database run record
   * @returns {Object} Normalized run object
   */
  #processDbRun(dbRun) {
    let status = dbRun.status;
    let exitCode = dbRun.exitCode;

    // If DB shows "running" but we don't have the process in memory,
    // it's an orphaned run (server restarted, process died unexpectedly, etc.)
    if (dbRun.status === 'running' && !this.processes.has(dbRun.id)) {
      this.#markOrphanedRunAsError(dbRun);
      status = 'error';
      exitCode = -1;
    }

    return {
      runId: dbRun.id,
      buttonId: dbRun.buttonId,
      status,
      output: dbRun.output,
      exitCode,
      startedAt: dbRun.startedAt,
    };
  }

  getRunsBySession(sessionId) {
    const runs = [];

    // Add currently running processes
    for (const [runId, entry] of this.processes) {
      if (entry.sessionId === sessionId) {
        runs.push({
          runId,
          buttonId: entry.buttonId,
          status: 'running',
          output: entry.output,
          exitCode: undefined,
          startedAt: entry.startTime,
        });
      }
    }

    // Add latest completed runs from database (one per button, no time limit)
    // Note: commandRuns might not be available in test environments
    if (commandRuns && typeof commandRuns.getLatestRunsForSession === 'function') {
      try {
        const dbRuns = commandRuns.getLatestRunsForSession(sessionId);
        for (const dbRun of dbRuns) {
          // Don't duplicate running processes
          const isRunningInMemory = runs.some((r) => r.runId === dbRun.id);
          if (!isRunningInMemory) {
            runs.push(this.#processDbRun(dbRun));
          }
        }
      } catch (err) {
        console.error(
          `[commandRunner.getRunsBySession] Error fetching database runs for sessionId: ${sessionId}`,
          err
        );
      }
    }

    return runs;
  }
}

// Singleton instance
export const commandRunner = new CommandRunner();

import { sessions, messages } from '../database.js';
import { schedulerService } from './schedulerService.js';

/**
 * Check if error message matches token limit patterns
 * @param {string} message - Error message to check
 * @returns {boolean} True if matches token limit error
 */
export function matchesTokenLimitError(message) {
  const patterns = [
    'token',
    'context length',
    'max_tokens',
    'context window',
    'limit',           // catches "You've hit your limit"
    'quota',
    'rate limit',
    'exceeded',        // catches usage exceeded messages
    'cap',             // catches usage cap messages
  ];

  return patterns.some(pattern => message.includes(pattern));
}

/**
 * Check if error message matches service error patterns
 * @param {string} message - Error message to check
 * @returns {boolean} True if matches service error
 */
export function matchesServiceError(message) {
  const patterns = [
    'overloaded',
    'rate limit',
    '503',
    '529',
    'unavailable',
    'service unavailable',
    'too many requests',
  ];

  return patterns.some(pattern => message.includes(pattern));
}

/**
 * Get the last assistant message for a session
 * @param {string} sessionId - Session ID
 * @returns {object|null} Last assistant message or null
 */
function getLastAssistantMessage(sessionId) {
  try {
    const sessionMessages = messages.getBySessionId(sessionId);
    const assistantMessages = sessionMessages.filter(msg => msg.role === 'assistant');
    return assistantMessages.length > 0 ? assistantMessages[assistantMessages.length - 1] : null;
  } catch (error) {
    console.error('[SessionManager] Error getting last assistant message:', error);
    return null;
  }
}

/**
 * Check if an error should trigger automatic rescheduling
 * @param {object} session - Session object
 * @param {Error} error - Error that occurred
 * @param {string} sessionId - Session ID
 * @returns {boolean} True if should reschedule
 */
export function shouldRescheduleOnError(session, error, sessionId = null) {
  const errorMessage = error.message.toLowerCase();

  // Check if auto-reschedule is enabled first (master switch)
  if (!session.autoRescheduleEnabled) {
    console.log('[SessionManager] autoRescheduleEnabled is false, skipping all rescheduling');
    return false;
  }

  // Check exception message first (existing behavior)
  if (session.rescheduleOnTokenLimit) {
    if (matchesTokenLimitError(errorMessage)) {
      console.log('[SessionManager] Token limit error detected, rescheduling will be attempted');
      console.log('[SessionManager] Error:', error.message);
      console.log('[SessionManager] Session config: rescheduleOnTokenLimit=true, rescheduleDelayMinutes=', session.rescheduleDelayMinutes);
      return true;
    }
  } else {
    console.log('[SessionManager] rescheduleOnTokenLimit is false, skipping token limit rescheduling');
  }

  if (session.rescheduleOnServiceError) {
    if (matchesServiceError(errorMessage)) {
      console.log('[SessionManager] Service error detected, rescheduling will be attempted');
      console.log('[SessionManager] Error:', error.message);
      console.log('[SessionManager] Session config: rescheduleOnServiceError=true, rescheduleDelayMinutes=', session.rescheduleDelayMinutes);
      return true;
    }
  } else {
    console.log('[SessionManager] rescheduleOnServiceError is false, skipping service error rescheduling');
  }

  // NEW: Also check last assistant message if available
  if (sessionId) {
    const lastAssistantMessage = getLastAssistantMessage(sessionId);
    if (lastAssistantMessage) {
      const messageContent = lastAssistantMessage.content.toLowerCase();

      if (session.rescheduleOnTokenLimit) {
        if (matchesTokenLimitError(messageContent)) {
          console.log('[SessionManager] Token limit detected in assistant message, rescheduling');
          console.log('[SessionManager] Assistant message:', lastAssistantMessage.content);
          console.log('[SessionManager] Session config: rescheduleOnTokenLimit=true, rescheduleDelayMinutes=', session.rescheduleDelayMinutes);
          return true;
        }
      }

      if (session.rescheduleOnServiceError) {
        if (matchesServiceError(messageContent)) {
          console.log('[SessionManager] Service error detected in assistant message, rescheduling');
          console.log('[SessionManager] Assistant message:', lastAssistantMessage.content);
          console.log('[SessionManager] Session config: rescheduleOnServiceError=true, rescheduleDelayMinutes=', session.rescheduleDelayMinutes);
          return true;
        }
      }
    }
  }

  console.log('[SessionManager] Error does not match any rescheduling triggers');
  console.log('[SessionManager] Session config: rescheduleOnTokenLimit=', session.rescheduleOnTokenLimit, ', rescheduleOnServiceError=', session.rescheduleOnServiceError);
  return false;
}

/**
 * Check if session should be proactively rescheduled based on token count
 * Called after processing each message to check token thresholds
 * @param {string} sessionId - Session ID
 * @returns {Promise<boolean>} True if rescheduled
 */
export async function _checkProactiveReschedule(sessionId) {
  const session = sessions.getById(sessionId);
  if (!session || !session.rescheduleAtTokenCount) {
    return false;
  }

  // Check if auto-reschedule is enabled first (master switch)
  if (!session.autoRescheduleEnabled) {
    console.log('[SessionManager] autoRescheduleEnabled is false, skipping proactive rescheduling');
    return false;
  }

  const totalTokens = session.inputTokens + session.outputTokens;
  if (totalTokens >= session.rescheduleAtTokenCount) {
    console.log(
      `[SessionManager] Proactive token threshold reached: ${totalTokens.toLocaleString()}/${session.rescheduleAtTokenCount.toLocaleString()}`
    );

    // Check if we've reached limits
    if (schedulerService.hasReachedLimits(session)) {
      console.log('[SessionManager] Cannot reschedule - limits reached');
      return false;
    }

    // Gracefully reschedule
    await schedulerService.rescheduleSession(
      sessionId,
      `Token threshold reached (${totalTokens.toLocaleString()} tokens)`
    );
    return true;
  }

  return false;
}

import { sessions, messages, workLogs, conversations } from '../database.js';
import { broadcastToSession, broadcastToProject } from '../websocket.js';
import { WS_MESSAGE_TYPES } from '@circuschief/shared';
import { updateTodos } from './todoStore.js';
import * as summaryService from './summaryService.js';
import * as diffService from './diffService.js';
import * as kanbanService from './kanbanService.js';
import {
  handleMessageStart,
  handleMessageDelta,
  handleTextDelta as _handleTextDelta,
  handleResultUsage,
} from './streamUsageHandler.js';

// ── Shared module-level state ──────────────────────────────────────────────

/** @type {Map<string, string|null>} Track last message ID for end-of-turn work log association */
export const lastMessageIds = new Map();

/** @type {Map<string, string>} Accumulate thinking content per session */
export const thinkingAccumulators = new Map();

/** @type {Map<string, string>} Accumulate text content per session */
export const textAccumulators = new Map();

/** @type {Map<string, { controller: AbortController }>} */
export const activeSessions = new Map();

/** @type {Map<string, string>} Map sessionId -> conversationId for current turn */
export const activeConversationIds = new Map();

/** @type {Map<string, string>} Track current model per session (updated on system.init) */
export const currentModels = new Map();

/** @type {Map<string, Set<string>>} Track tool_use IDs that have already been logged per session */
export const loggedToolUseIds = new Map();

// ── Helper functions ───────────────────────────────────────────────────────

/**
 * Create and broadcast a work log entry
 * Work logs are always created as unassociated during the turn,
 * then associated with the message when the turn completes.
 * @param {string} sessionId
 * @param {string} type - 'thinking', 'tool_input', or 'tool_output'
 * @param {string} content
 * @param {string|null} toolName
 */
export function createWorkLog(sessionId, type, content, toolName = null) {
  // Always create as unassociated - will be associated at end of turn
  const log = workLogs.create(sessionId, type, content, { messageId: null, toolName });
  broadcastToSession(sessionId, WS_MESSAGE_TYPES.SESSION_WORK_LOG, {
    sessionId,
    log
  });
  return log;
}

/**
 * Associate pending work logs with a message and broadcast the event
 * @param {string} sessionId
 * @param {string} messageId
 */
export function associateAndBroadcastWorkLogs(sessionId, messageId) {
  const associatedCount = workLogs.associatePendingLogs(sessionId, messageId);
  if (associatedCount > 0) {
    broadcastToSession(sessionId, WS_MESSAGE_TYPES.SESSION_WORK_LOGS_ASSOCIATED, {
      sessionId,
      messageId,
    });
  }
  return associatedCount;
}

/**
 * Broadcast session status update
 * @param {string} sessionId
 * @param {string} status
 */
export function broadcastSessionStatus(sessionId, status) {
  // Broadcast to session subscribers (for session detail view)
  broadcastToSession(sessionId, WS_MESSAGE_TYPES.SESSION_STATUS, { sessionId, status });

  // Also broadcast SESSION_UPDATED to project subscribers (for session list updates)
  const session = sessions.getById(sessionId);
  if (session) {
    broadcastToProject(session.projectId, WS_MESSAGE_TYPES.SESSION_UPDATED, {
      projectId: session.projectId,
      sessionId,
      session: { ...session, status },
    });
  }
}

/**
 * Compute and broadcast changes state when turn completes
 * Called after status is set to "waiting" to provide real-time changes update
 * @param {string} sessionId
 * @param {string} projectId
 * @param {string} workingDirectory
 */
export async function broadcastChangesUpdate(sessionId, projectId, workingDirectory) {
  try {
    const changes = await diffService.getChanges(workingDirectory);
    const hasChanges = Boolean(changes.staged || changes.unstaged || changes.untracked);

    // Count total files with changes
    // Parse diff output to count unique files
    const parseFilesFromDiff = (diff) => {
      if (!diff) return 0;
      const matches = diff.match(/^diff --git a\/(.+) b\//gm) || [];
      return matches.length;
    };

    const stagedCount = parseFilesFromDiff(changes.staged);
    const unstagedCount = parseFilesFromDiff(changes.unstaged);
    const untrackedCount = parseFilesFromDiff(changes.untracked);
    const changeCount = stagedCount + unstagedCount + untrackedCount;

    // Broadcast to session subscribers
    broadcastToSession(sessionId, WS_MESSAGE_TYPES.CHANGES_UPDATE, {
      sessionId,
      hasChanges,
      changeCount,
    });
  } catch (error) {
    // Silently fail - changes indicator is not critical
    // This handles cases like non-git directories or permission errors
    console.error(`Failed to compute changes for session ${sessionId}:`, error.message);
  }
}

// ── Event-type-specific handlers ────────────────────────────────────────────

/**
 * Handle 'system' events (e.g. system.init)
 * @param {string} sessionId
 * @param {Object} event
 */
function handleSystemEvent(sessionId, event) {
  // Store Claude's session info
  if (event.subtype !== 'init') return;

  // Save Claude session ID to the active conversation for context isolation
  const activeConversation = conversations.getActiveBySessionId(sessionId);
  if (activeConversation) {
    conversations.update(activeConversation.id, {
      claudeSessionId: event.session_id,
    });
  }
  // Track current model for this session (used when creating messages)
  currentModels.set(sessionId, event.model);
  // Capture available slash commands (do NOT update model here — session.model
  // tracks the user-requested short format; this SDK model is stored in currentModels)
  sessions.update(sessionId, {
    slashCommands: JSON.stringify(event.slash_commands || []),
  });
  // Reset message tracking for new session
  lastMessageIds.delete(sessionId);
}

/**
 * Handle 'assistant' events — save messages, update todos, log tool use
 * @param {string} sessionId
 * @param {Object} event
 */
function handleAssistantEvent(sessionId, event) {
  // Extract text content from assistant message
  const textContent = event.message?.content
    ?.filter((c) => c.type === 'text')
    ?.map((c) => c.text)
    ?.join('\n');

  // Extract tool use for logging
  const toolUseBlocks = event.message?.content?.filter((c) => c.type === 'tool_use') || [];

  // NOTE: Do NOT use assistant event usage for broadcasting
  // The stream events already provide real-time usage updates via message_start and message_delta
  // Using assistant event would double-count the usage

  if (textContent) {
    handleAssistantTextContent(sessionId, textContent, toolUseBlocks);
  }

  // Check for TodoWrite tool and update todos
  // NOTE: This must be OUTSIDE the if (textContent) block because Claude can call
  // TodoWrite without any accompanying text content (tool-only messages)
  handleTodoWriteIfPresent(sessionId, toolUseBlocks);

  // Note: Thinking content is logged via stream_event -> content_block_stop
  // to avoid duplicates (since includePartialMessages is always enabled)

  // Log tool use inputs (dedup by tool_use ID to prevent duplicates from partial assistant events)
  logToolUseInputs(sessionId, toolUseBlocks);
}

/**
 * Save assistant text content as a message and broadcast it
 * @param {string} sessionId
 * @param {string} textContent
 * @param {Array} toolUseBlocks
 */
function handleAssistantTextContent(sessionId, textContent, toolUseBlocks) {
  const toolUse = toolUseBlocks.length > 0 ? toolUseBlocks : null;
  const activeConversation = conversations.getActiveBySessionId(sessionId);
  const conversationId = activeConversation?.id || null;
  const currentModel = currentModels.get(sessionId) || null;
  const message = messages.create(sessionId, 'assistant', textContent, { toolUse, conversationId, model: currentModel });

  // Associate pending work logs with this message immediately
  // This ensures work logs are attached to the correct message, not just the last one
  associateAndBroadcastWorkLogs(sessionId, message.id);

  // Track the message ID in case there are trailing work logs after the last message
  lastMessageIds.set(sessionId, message.id);

  // Broadcast message with conversationId for proper routing
  broadcastToSession(sessionId, WS_MESSAGE_TYPES.SESSION_MESSAGE, {
    message,
    conversationId, // Include conversation context to prevent ambiguity
  });

  // Clear partial text on client now that complete message has been sent
  broadcastToSession(sessionId, WS_MESSAGE_TYPES.SESSION_PARTIAL, {
    sessionId,
    text: '',
  });

  // Note: Per-message onSessionActivity removed to reduce redundant summary generation.
  // Summary generation is triggered only on turn completion (waiting state) and session complete.
}

/**
 * Check for TodoWrite tool in toolUseBlocks and update todos if present
 * @param {string} sessionId
 * @param {Array} toolUseBlocks
 */
function handleTodoWriteIfPresent(sessionId, toolUseBlocks) {
  if (toolUseBlocks.length === 0) return;
  const todoWrite = toolUseBlocks.find((t) => t.name === 'TodoWrite');
  if (!todoWrite?.input?.todos) return;
  // Get active conversation to scope todos to it
  const activeConv = conversations.getActiveBySessionId(sessionId);
  if (activeConv) {
    updateTodos(sessionId, activeConv.id, todoWrite.input.todos);
  }
}

/**
 * Log tool use inputs, deduplicating by tool_use ID
 * @param {string} sessionId
 * @param {Array} toolUseBlocks
 */
function logToolUseInputs(sessionId, toolUseBlocks) {
  if (!loggedToolUseIds.has(sessionId)) {
    loggedToolUseIds.set(sessionId, new Set());
  }
  const loggedIds = loggedToolUseIds.get(sessionId);
  for (const toolUse of toolUseBlocks) {
    if (toolUse.id && loggedIds.has(toolUse.id)) continue;
    if (toolUse.id) loggedIds.add(toolUse.id);
    const toolInput = JSON.stringify(toolUse.input, null, 2);
    createWorkLog(sessionId, 'tool_input', toolInput, toolUse.name);
  }
}

/**
 * Handle 'tool_result' events — log tool outputs
 * @param {string} sessionId
 * @param {Object} event
 */
function handleToolResultEvent(sessionId, event) {
  // Log tool results/outputs
  const content = event.content || event.result || '';
  const toolName = event.tool_name || event.name || 'unknown';

  // Handle different content formats
  const logContent = formatToolResultContent(content);

  if (logContent) {
    createWorkLog(sessionId, 'tool_output', logContent, toolName);
  }
}

/**
 * Format tool result content for logging
 * @param {*} content
 * @returns {string}
 */
function formatToolResultContent(content) {
  if (typeof content === 'string') return content;
  if (Array.isArray(content)) {
    return content
      .map((c) => (c.type === 'text' ? c.text : JSON.stringify(c)))
      .join('\n');
  }
  return JSON.stringify(content, null, 2);
}

/**
 * Handle 'stream_event' wrapper — dispatches to sub-handlers based on event.event.type
 * @param {string} sessionId
 * @param {Object} event
 */
function handleStreamEventType(sessionId, event) {
  const innerType = event.event?.type;
  const handler = streamSubHandlers[innerType];
  if (handler) {
    handler(sessionId, event);
  }
}

/**
 * Handle stream_event > message_start — clear text accumulator, then delegate to streamUsageHandler
 * @param {string} sessionId
 * @param {Object} event
 */
function handleMessageStartWrapper(sessionId, event) {
  // Clear text accumulator for fresh message
  textAccumulators.delete(sessionId);
  handleMessageStart(sessionId, event);
}

/**
 * Handle stream_event > content_block_delta — text and thinking deltas
 * @param {string} sessionId
 * @param {Object} event
 */
function handleContentBlockDelta(sessionId, event) {
  const delta = event.event.delta;

  if (delta?.type === 'text_delta' && delta.text) {
    _handleTextDelta(sessionId, delta, textAccumulators);
  }

  // Handle thinking delta - accumulate and broadcast partial (don't create work log yet)
  if (delta?.type === 'thinking_delta' && delta.thinking) {
    handleThinkingDelta(sessionId, delta);
  }
}

/**
 * Handle thinking_delta within content_block_delta — accumulate thinking
 * @param {string} sessionId
 * @param {Object} delta
 */
function handleThinkingDelta(sessionId, delta) {
  const current = thinkingAccumulators.get(sessionId) || '';
  const accumulated = current + delta.thinking;
  thinkingAccumulators.set(sessionId, accumulated);

  // Broadcast partial thinking for real-time display
  broadcastToSession(sessionId, WS_MESSAGE_TYPES.SESSION_THINKING_PARTIAL, {
    sessionId,
    thinking: accumulated,
  });
}

/**
 * Handle stream_event > content_block_stop — finalize accumulated thinking and text
 * @param {string} sessionId
 * @param {Object} _event
 */
function handleContentBlockStop(sessionId, _event) {
  const accumulated = thinkingAccumulators.get(sessionId);
  if (accumulated) {
    // Create a single work log entry with the complete thinking content
    createWorkLog(sessionId, 'thinking', accumulated);
    thinkingAccumulators.delete(sessionId);

    // Clear partial thinking on client
    broadcastToSession(sessionId, WS_MESSAGE_TYPES.SESSION_THINKING_PARTIAL, {
      sessionId,
      thinking: null,
    });
  }

  // Clear text accumulator when content block finishes
  // The text has been finalized into a message
  textAccumulators.delete(sessionId);
}

/**
 * Handle 'result' events — errors and final usage
 * @param {string} sessionId
 * @param {Object} event
 */
function handleResultEvent(sessionId, event) {
  if (event.subtype === 'error') {
    handleResultError(sessionId, event);
  } else {
    handleResultSuccess(sessionId, event);
  }
  // Note: Don't clear lastMessageIds here - let the post-loop association code handle it.
  // Clearing here was causing work logs to never be associated because the 'result' event
  // arrives before the loop ends, deleting the messageId before association can happen.
}

/**
 * Handle result error subtype
 * @param {string} sessionId
 * @param {Object} event
 */
function handleResultError(sessionId, event) {
  sessions.update(sessionId, { status: 'error', error: event.error });
  broadcastToSession(sessionId, WS_MESSAGE_TYPES.SESSION_ERROR, { sessionId, error: event.error });
  // Broadcast error status to project subscribers for session list updates
  broadcastSessionStatus(sessionId, 'error');
  // Extract PR URL before generating summary (PR may have been created before error)
  summaryService.extractPrUrlIfNeeded(sessionId);
  // Generate summary on error
  summaryService.onSessionComplete(sessionId);
}

/**
 * Handle result success subtype — store cost and usage
 * @param {string} sessionId
 * @param {Object} event
 */
function handleResultSuccess(sessionId, event) {
  // Store cost info and broadcast to project subscribers
  if (event.total_cost_usd !== undefined) {
    sessions.update(sessionId, { costUsd: event.total_cost_usd });
  }

  // Store final usage stats to conversation (Issue #175)
  if (event.usage || event.modelUsage) {
    handleResultUsage(sessionId, event);
  }
}


// ── Dispatch maps ───────────────────────────────────────────────────────────

/** @type {Record<string, (sessionId: string, event: Object) => void>} */
const streamSubHandlers = {
  message_start: handleMessageStartWrapper,
  message_delta: handleMessageDelta,
  content_block_delta: handleContentBlockDelta,
  content_block_stop: handleContentBlockStop,
};

/** @type {Record<string, (sessionId: string, event: Object) => void>} */
const eventHandlers = {
  system: handleSystemEvent,
  assistant: handleAssistantEvent,
  tool_result: handleToolResultEvent,
  stream_event: handleStreamEventType,
  result: handleResultEvent,
};

// ── Main stream event handler ──────────────────────────────────────────────

/**
 * Handle a stream event from Claude SDK
 * @param {string} sessionId
 * @param {Object} event
 */
export async function handleStreamEvent(sessionId, event) {
  // Check if session has been cleaned up (aborted/deleted) - don't process events for deleted sessions
  if (!activeSessions.has(sessionId)) {
    return;
  }

  const handler = eventHandlers[event.type];
  if (handler) {
    handler(sessionId, event);
  }
}

/**
 * Clean up all session state from the Maps
 * Called in the finally block of session execution
 * @param {string} sessionId
 * @param {boolean} includeConversationId - Whether to also clean up activeConversationIds
 */
export function cleanupSessionState(sessionId, includeConversationId = false) {
  textAccumulators.delete(sessionId);
  thinkingAccumulators.delete(sessionId);
  currentModels.delete(sessionId);
  loggedToolUseIds.delete(sessionId);
  activeSessions.delete(sessionId);
  if (includeConversationId) {
    activeConversationIds.delete(sessionId);
  }
}

/**
 * Handle post-turn completion logic (after stream loop ends successfully)
 * Encapsulates the duplicated completion block from runSession/continueSession/continueSessionWithExistingMessage
 * @param {string} sessionId
 * @param {string} workingDirectory
 * @param {{ handleTemplateTriggerIfNeeded?: Function, checkProactiveReschedule?: Function, handleAutoSendIfNeeded?: Function }} callbacks
 */
export async function handleTurnCompletion(sessionId, workingDirectory, callbacks = {}) {
  const { handleTemplateTriggerIfNeeded, checkProactiveReschedule: _checkProactiveReschedule, handleAutoSendIfNeeded } = callbacks;
  // Associate work logs with the last message now that the turn is complete
  const lastMessageId = lastMessageIds.get(sessionId);
  if (lastMessageId) {
    associateAndBroadcastWorkLogs(sessionId, lastMessageId);
    lastMessageIds.delete(sessionId);
  }

  // Session ready for follow-up - set to waiting instead of completed
  const activeSession = activeSessions.get(sessionId);
  if (activeSession && !activeSession.controller?.signal?.aborted) {
    sessions.update(sessionId, { status: 'waiting' });
    broadcastSessionStatus(sessionId, 'waiting');

    // Check if session should be proactively rescheduled based on token threshold
    if (_checkProactiveReschedule) {
      const wasRescheduled = await _checkProactiveReschedule(sessionId);
      if (wasRescheduled) {
        return true; // Session was rescheduled, don't continue with normal completion
      }
    }

    // Extract PR URL immediately (lightweight, no API call)
    summaryService.extractPrUrlIfNeeded(sessionId);
    // Trigger debounced summary generation on turn completion (not complete yet)
    summaryService.onSessionActivity(sessionId);

    // Broadcast changes update when turn completes (real-time indicator)
    const currentSession = sessions.getById(sessionId);
    if (currentSession) {
      await broadcastChangesUpdate(sessionId, currentSession.projectId, workingDirectory);
    }

    // Handle kanban lane movements based on targetLaneId
    await kanbanService.handleTurnCompletion(sessionId);

    // Auto-send queued prompt if enabled (runs BEFORE template trigger)
    let autoSendFired = false;
    if (handleAutoSendIfNeeded) {
      autoSendFired = await handleAutoSendIfNeeded(sessionId);
    }

    // Only trigger next template if auto-send did NOT fire
    // (if auto-send fired, template will trigger after that turn completes)
    if (!autoSendFired && handleTemplateTriggerIfNeeded) {
      await handleTemplateTriggerIfNeeded(sessionId);
    }
  }
  return false;
}

/**
 * Handle session error with optional rescheduling
 * Encapsulates the duplicated error handling block from runSession/continueSession/continueSessionWithExistingMessage
 * @param {string} sessionId
 * @param {Error} error
 * @param {{ controller: AbortController, shouldRescheduleOnError: Function, schedulerService: Object, errorLabel?: string, broadcastConversationState?: boolean, handleTemplateTriggerIfNeeded?: Function }} options
 */
export async function handleSessionError(sessionId, error, options = {}) {
  const { controller, shouldRescheduleOnError, schedulerService } = options;
  const errorLabel = options.errorLabel || 'Session error';
  console.error(`${errorLabel}:`, error);
  console.error('Error stack:', error.stack);
  if (!controller.signal.aborted) {
    // Check if we should reschedule instead of marking as error
    const session = sessions.getById(sessionId);
    if (session && shouldRescheduleOnError(session, error, sessionId)) {
      const rescheduled = await schedulerService.rescheduleSession(sessionId, error.message);
      if (rescheduled) {
        console.log(`[SessionManager] Session ${sessionId} rescheduled due to error`);
        return true; // Rescheduled, don't throw
      }
      // If rescheduling failed (limits reached), fall through to error handling
    }

    // Normal error handling (no reschedule or reschedule limits reached)
    sessions.update(sessionId, { status: 'error', error: error.message });
    broadcastToSession(sessionId, WS_MESSAGE_TYPES.SESSION_ERROR, { sessionId, error: error.message });

    // Optionally broadcast final conversation state (continueSession does this)
    if (options.broadcastConversationState) {
      const errorConversationId = activeConversationIds.get(sessionId);
      if (errorConversationId) {
        const finalConversation = conversations.getById(errorConversationId);
        if (finalConversation) {
          broadcastToSession(sessionId, WS_MESSAGE_TYPES.CONVERSATION_UPDATED, {
            sessionId,
            conversation: finalConversation,
          });
        }
      }
      // Broadcast error status to project and session subscribers (terminal signal)
      broadcastSessionStatus(sessionId, 'error');
    }

    // Extract PR URL before generating summary (PR may have been created before error)
    summaryService.extractPrUrlIfNeeded(sessionId);
    // Trigger summary generation on error
    summaryService.onSessionComplete(sessionId);

    // Trigger next template if configured (e.g., session completed work but process exited with error code)
    // Wrapped in try/catch because we are already in the error path — a template failure
    // must not mask the original error or prevent handleSessionError from returning.
    if (options.handleTemplateTriggerIfNeeded) {
      try {
        await options.handleTemplateTriggerIfNeeded(sessionId);
      } catch (templateError) {
        console.error(`[handleSessionError] Template trigger failed for session ${sessionId}:`, templateError);
      }
    }
  }
  return false; // Not rescheduled
}

/**
 * Session summary orchestration service.
 *
 * Coordinates summary generation, staleness detection, lifecycle hooks,
 * and concurrency management. Delegates to extracted modules:
 * - summaryClaudeClient.js — Claude SDK interaction
 * - summaryPrompts.js — prompt templates, parsing, formatting
 * - prUrlService.js — PR URL extraction, validation, enrichment
 * - childSessionContext.js — child session hierarchy and file aggregation
 * - withConcurrencyGuard.js — concurrency guard utility
 * - summaryBroadcast.js — WebSocket broadcast helpers
 */

import { sessions, messages, sessionSummaries, projects, settings } from '../database.js';
import { createConcurrencyGuard } from './withConcurrencyGuard.js';
import { callClaude } from './summaryClaudeClient.js';
import {
  MAX_MESSAGES,
  MIN_MESSAGES_FOR_SUMMARY,
  MAX_RETRIES,
  DEFAULT_SESSION_TITLE_PROMPT,
  SUMMARY_SYSTEM_PROMPT,
  formatMessages,
  buildIncrementalPrompt,
  parseSummaryResponse,
  trackMessageMetadata,
  stripMarkdownCodeBlock,
} from './summaryPrompts.js';
import { extractPrUrlIfNeeded, parsePrUrl, validatePrUrl, enrichPrData } from './prUrlService.js';
import { getChildSessions, buildChildSessionContext, aggregateFilesModified } from './childSessionContext.js';
import { broadcastSummaryUpdate, broadcastGeneratingStatus, broadcastSessionUpdate } from './summaryBroadcast.js';
import { isSummaryStale } from './summaryStaleCheck.js';

// Note: prStatusService is imported dynamically in onSessionComplete to avoid circular dependency

// Create the concurrency guard instance for summary generation
const guard = createConcurrencyGuard();

/**
 * Generate summary for a session using Claude Code SDK (with concurrency guard)
 * Only one generation can be in-flight per session at a time. If a generation is already
 * running, the call is coalesced and a single follow-up generation is scheduled after completion.
 * @param {string} sessionId
 * @param {number} retryCount - Internal retry counter (do not set manually)
 * @param {boolean} force - Force generation even if summary is current (default: false)
 * @param {boolean} userInitiated - Whether triggered by explicit user action (default: false)
 * @returns {Promise<Object|null>}
 */
export async function generateSummary(sessionId, retryCount = 0, force = false, userInitiated = false) {
  return guard.run(
    sessionId,
    () => _doGenerateSummary(sessionId, retryCount, force, userInitiated),
    {
      bypass: userInitiated,
      onFollowUp: (key) => generateSummary(key),
    }
  );
}

/**
 * Perform early-exit checks to decide whether summary generation should proceed.
 * Returns an object with the decision and any data needed downstream.
 * @param {string} sessionId
 * @param {boolean} force
 * @param {boolean} userInitiated
 * @returns {{ skip: true, result: Object|null } | { skip: false, session: Object, globalSettings: Object, existingSummary: Object|null, allMessages: Array }}
 */
function shouldGenerateSummary(sessionId, force, userInitiated) {
  const session = sessions.getById(sessionId);
  if (!session) {
    console.warn(`[SummaryService] Session ${sessionId} not found for summary generation`);
    return { skip: true, result: null };
  }

  const globalSettings = settings.getSummarySettings();
  if (!userInitiated && globalSettings?.disableSessionSummaries) {
    console.log(`[SummaryService] Session summaries disabled globally, skipping generation`);
    return { skip: true, result: null };
  }

  const existingSummary = sessionSummaries.getBySessionId(sessionId);

  if (existingSummary?.prMerged) {
    console.log(`[SummaryService] Session ${sessionId} has merged PR, skipping regeneration`);
    return { skip: true, result: existingSummary };
  }

  const allMessages = messages.getBySessionId(sessionId);

  if (!force && !isSummaryStale(sessionId)) {
    console.log(`[SummaryService] Summary for ${sessionId} is current, skipping regeneration`);
    return { skip: true, result: existingSummary };
  }

  return { skip: false, session, globalSettings, existingSummary, allMessages };
}

/**
 * Fetch conversation context: build child session context and the prompt for Claude.
 * @param {string} sessionId
 * @param {Object} context
 * @param {Object|null} context.existingSummary
 * @param {Array} context.recentMessages
 * @param {Object} context.session
 * @param {Object} context.globalSettings
 * @returns {{ prompt: string, childContext: Object }}
 */
function fetchConversationContext(sessionId, { existingSummary, recentMessages, session, globalSettings }) {
  const childContext = buildChildSessionContext(sessionId);
  const prompt = buildIncrementalPrompt(existingSummary, recentMessages, session.status, {
    projectTitlePrompt: globalSettings?.sessionTitlePrompt,
    childContext,
  });
  return { prompt, childContext };
}

/**
 * Persist the generated summary and broadcast all related updates.
 * Handles: metadata tracking, file aggregation, PR enrichment, upsert,
 * project repo auto-population, session name/prUrl update, and broadcasts.
 * @param {string} sessionId
 * @param {Object} summaryDataInput - parsed summary data (mutated in place)
 * @param {Object} session
 * @param {Array} allMessages
 * @returns {Promise<Object>} the persisted summary record
 */
async function saveSummaryResult(sessionId, summaryDataInput, session, allMessages) {
  const summaryData = summaryDataInput;
  // Clean up internal flag before saving
  delete summaryData._parseFailed;

  // Add message count and last message ID for staleness tracking
  trackMessageMetadata(summaryData, allMessages);

  // For root sessions (no parent), aggregate files from all child sessions
  if (!session.parentSessionId) {
    summaryData.filesModified = aggregateFilesModified(sessionId, summaryData.filesModified);
  }

  // Validate and enrich PR URL
  const prUrl = summaryData.prUrl || session.prUrl;
  if (prUrl) {
    const project = projects.getById(session.projectId);
    await enrichPrData(summaryData, prUrl, project?.repoUrl, sessionId);
  }

  // Upsert summary
  const summary = sessionSummaries.upsert(sessionId, summaryData);

  // Auto-populate project repo URL if not already set
  autoPopulateProjectRepoUrl(session, summaryData);

  // Update session name and prUrl, then broadcast
  updateSessionFromSummary(sessionId, session, summaryData);

  // Broadcast updated summary to session and project subscribers
  broadcastSummaryUpdate(sessionId, session.projectId, summary);

  return summary;
}

/**
 * Auto-populate the project's repoUrl from summary data if not already set.
 * @param {Object} session
 * @param {Object} summaryData
 */
function autoPopulateProjectRepoUrl(session, summaryData) {
  const project = projects.getById(session.projectId);
  if (project.repoUrl || (!summaryData.prUrl && !summaryData.repositoryUrl)) return;

  let extractedRepoUrl = summaryData.repositoryUrl;

  if (!extractedRepoUrl && summaryData.prUrl) {
    const prMatch = summaryData.prUrl.match(/^(https:\/\/github\.com\/[^/]+\/[^/]+)(?:\/|$)/);
    if (prMatch) {
      extractedRepoUrl = prMatch[1];
    }
  }

  if (extractedRepoUrl) {
    try {
      projects.update(session.projectId, { repoUrl: extractedRepoUrl });
      console.log(`[SummaryService] Auto-populated repo URL for project ${session.projectId}: ${extractedRepoUrl}`);
    } catch (error) {
      console.warn(`[SummaryService] Failed to auto-populate repo URL for project ${session.projectId}:`, error.message);
    }
  }
}

/**
 * Update session name and prUrl from summary data and broadcast changes.
 * @param {string} sessionId
 * @param {Object} session
 * @param {Object} summaryData
 */
function updateSessionFromSummary(sessionId, session, summaryData) {
  if (summaryData.sessionTitle || summaryData.prUrl) {
    const updateData = {};
    const freshSession = sessions.getById(sessionId);

    if (summaryData.sessionTitle && !freshSession.manuallyNamed) {
      updateData.name = summaryData.sessionTitle;
    }

    if (summaryData.prUrl) {
      updateData.prUrl = summaryData.prUrl;
    }

    const updatedSession = sessions.update(sessionId, updateData);

    if (summaryData.prUrl) {
      propagatePrUrlToParent(sessionId, summaryData.prUrl);
    }

    broadcastSessionUpdate(sessionId, session.projectId, updatedSession);
  } else if (session.projectId) {
    broadcastSessionUpdate(sessionId, session.projectId, sessions.getById(sessionId));
  }
}

/**
 * Handle sessions with too few messages by creating a minimal summary.
 * @param {string} sessionId
 * @param {Object} session
 * @param {Array} allMessages
 * @returns {Object} the minimal summary
 */
function createMinimalSummary(sessionId, session, allMessages) {
  console.log(`[SummaryService] Session ${sessionId} has only ${allMessages.length} messages (minimum ${MIN_MESSAGES_FOR_SUMMARY}), creating minimal summary`);

  const lastMessage = allMessages.length > 0 ? allMessages[allMessages.length - 1] : null;

  const minimalSummary = {
    shortSummary: 'Session in progress',
    fullSummary: `Session with ${allMessages.length} message${allMessages.length !== 1 ? 's' : ''}`,
    keyActions: [],
    filesModified: [],
    outcome: session.status === 'stopped' ? 'partial' : session.status === 'error' ? 'failed' : 'ongoing',
    messageCount: allMessages.length,
    lastSummarizedMessageId: lastMessage ? lastMessage.id : null,
  };

  const summary = sessionSummaries.upsert(sessionId, minimalSummary);

  broadcastSummaryUpdate(sessionId, session.projectId, summary);

  if (session.projectId) {
    broadcastSessionUpdate(sessionId, session.projectId, sessions.getById(sessionId));
  }

  return summary;
}

/**
 * Internal implementation of generateSummary (called by concurrency guard wrapper)
 * @param {string} sessionId
 * @param {number} retryCount
 * @param {boolean} force
 * @param {boolean} userInitiated
 * @returns {Promise<Object|null>}
 */
async function _doGenerateSummary(sessionId, retryCount = 0, force = false, userInitiated = false) {
  try {
    // Early-exit checks
    const check = shouldGenerateSummary(sessionId, force, userInitiated);
    if (check.skip) return check.result;

    const { session, globalSettings, existingSummary, allMessages } = check;
    const recentMessages = allMessages.slice(-MAX_MESSAGES);

    // Broadcast that we're generating (do this early so UI always gets the event)
    broadcastGeneratingStatus(sessionId, true);

    // Handle sessions with too few messages
    if (allMessages.length < MIN_MESSAGES_FOR_SUMMARY) {
      const summary = createMinimalSummary(sessionId, session, allMessages);
      broadcastGeneratingStatus(sessionId, false);
      return summary;
    }

    // Build conversation context and prompt
    const { prompt } = fetchConversationContext(sessionId, { existingSummary, recentMessages, session, globalSettings });

    // Call Claude via SDK
    const responseText = await callClaude(prompt, recentMessages, session.status, {
      logMeta: { sessionId, callType: 'generateSessionSummary' },
      systemPrompt: SUMMARY_SYSTEM_PROMPT,
    });

    // Parse response
    const summaryData = parseSummaryResponse(responseText);

    // Retry if parsing failed and we haven't exhausted retries
    if (summaryData._parseFailed && retryCount < MAX_RETRIES) {
      console.log(
        `[SummaryService] Parse failed for session ${sessionId}, retrying (attempt ${retryCount + 2}/${MAX_RETRIES + 1})`
      );
      const backoffMs = 1000 * (retryCount + 1);
      await new Promise((resolve) => setTimeout(resolve, backoffMs));
      return _doGenerateSummary(sessionId, retryCount + 1, force, userInitiated);
    }

    // Persist summary and broadcast updates
    const summary = await saveSummaryResult(sessionId, summaryData, session, allMessages);

    // Clear the generating flag so the UI knows generation is complete
    broadcastGeneratingStatus(sessionId, false);

    console.log(`[SummaryService] Successfully generated summary for session ${sessionId}`);

    // Propagate summary updates to parent sessions (workflow-aware)
    if (session.parentSessionId) {
      propagateToParent(sessionId);
    }

    return summary;
  } catch (error) {
    console.error(`[SummaryService] Failed to generate summary for session ${sessionId}:`, {
      error: error.message,
      stack: error.stack,
      sessionId,
    });

    // Broadcast that generation stopped
    broadcastGeneratingStatus(sessionId, false);

    return null;
  }
}

/**
 * Generate summary immediately and wait for completion (synchronous)
 * Used by template trigger to ensure summary is ready before creating new session
 * @param {string} sessionId
 * @returns {Promise<Object|null>}
 */
export async function generateSummaryNow(sessionId) {
  // Check if session summaries are disabled globally (early exit before concurrency bookkeeping)
  const globalSettings = settings.getSummarySettings();
  if (globalSettings?.disableSessionSummaries) {
    return null;
  }
  // Generate summary immediately and wait for completion
  return generateSummary(sessionId);
}

/**
 * Trigger summary generation on session activity (e.g., turn completion).
 * @param {string} sessionId
 */
export function onSessionActivity(sessionId) {
  // Early exit if session summaries are disabled globally
  const globalSettings = settings.getSummarySettings();
  if (globalSettings?.disableSessionSummaries) {
    return;
  }

  generateSummary(sessionId).catch((err) => {
    console.error(`[SummaryService] Failed to generate summary on activity for session ${sessionId}:`, err);
  });
}

/**
 * Called when session completes - generate immediately if summary is stale,
 * otherwise do a lightweight outcome-only DB update (no LLM call).
 * Also schedules follow-up CI checks for sessions with PRs.
 * @param {string} sessionId
 */
export function onSessionComplete(sessionId) {
  // Early exit if session summaries are disabled globally
  const globalSettings = settings.getSummarySettings();
  if (globalSettings?.disableSessionSummaries) {
    // Still schedule CI checks below, but skip all summary work
    const session = sessions.getById(sessionId);
    if (session?.prUrl) {
      const scheduleCiCheck = async () => {
        const prStatusService = await import('./prStatusService.js');
        prStatusService.checkSessionCiStatusNow(sessionId);
      };
      setTimeout(scheduleCiCheck, 2 * 60 * 1000);
      setTimeout(scheduleCiCheck, 5 * 60 * 1000);
    }
    return;
  }

  // Lightweight outcome update: if summary exists and is current,
  // just update the outcome field without calling the LLM
  const existingSummary = sessionSummaries.getBySessionId(sessionId);
  const session = sessions.getById(sessionId);
  if (existingSummary && !isSummaryStale(sessionId) && session) {
    const newOutcome = session.status === 'error' ? 'failed'
      : session.status === 'stopped' ? 'partial'
      : 'completed';
    if (existingSummary.outcome !== newOutcome) {
      sessionSummaries.upsert(sessionId, { ...existingSummary, outcome: newOutcome });
      console.log(`[SummaryService] Lightweight outcome update for session ${sessionId}: ${existingSummary.outcome} -> ${newOutcome}`);

      // Broadcast the updated summary
      const updatedSummary = sessionSummaries.getBySessionId(sessionId);
      broadcastSummaryUpdate(sessionId, session.projectId, updatedSummary);
    } else {
      console.log(`[SummaryService] Summary for session ${sessionId} is current and outcome unchanged, skipping generation`);
    }
    // Still schedule CI checks below
  } else {
    // Summary is stale or doesn't exist -- generate via LLM
    const currentSettings = settings.getSummarySettings();
    if (!currentSettings?.disableSessionSummaries) {
      generateSummary(sessionId);
    }
  }

  // Schedule follow-up CI checks for sessions with PRs
  const sessionForCi = session || sessions.getById(sessionId);
  if (sessionForCi?.prUrl) {
    // Use dynamic import to avoid circular dependency with prStatusService
    const scheduleCiCheck = async () => {
      const prStatusService = await import('./prStatusService.js');
      prStatusService.checkSessionCiStatusNow(sessionId);
    };

    // Check after 2 minutes (CI often takes a few minutes)
    setTimeout(scheduleCiCheck, 2 * 60 * 1000);

    // Check again after 5 minutes
    setTimeout(scheduleCiCheck, 5 * 60 * 1000);
  }
}

/**
 * Get summary for a session, generating if needed
 * @param {string} sessionId
 * @param {boolean} generateIfMissing - Whether to generate if no summary exists
 * @returns {Promise<Object|null>}
 */
export async function getSummary(sessionId, generateIfMissing = false) {
  let summary = sessionSummaries.getBySessionId(sessionId);

  if (!summary && generateIfMissing) {
    // Don't generate if session summaries are disabled globally
    const globalSettings = settings.getSummarySettings();
    if (globalSettings?.disableSessionSummaries) return null;
    summary = await generateSummary(sessionId);
  }

  return summary;
}

/**
 * Force regenerate summary for a session (user-initiated action)
 * This bypasses the global disable setting since the user explicitly requested it.
 * @param {string} sessionId
 * @returns {Promise<Object|null>}
 */
export async function regenerateSummary(sessionId) {
  return generateSummary(sessionId, 0, true, true);
}

