import { Liquid } from 'liquidjs';
import { sessions, sessionTemplates, sessionSummaries, projects } from '../database.js';
import { setupGitForSession } from './gitSessionSetup.js';
import { runSession } from './sessionManager.js';
import { broadcastToProject } from '../websocket.js';
import { WS_MESSAGE_TYPES } from '@circuschief/shared';

const liquid = new Liquid();

/**
 * Get the root session (the original session that started a template chain)
 * @param {Object} session - The current session
 * @returns {Object} The root session (or the current session if it has no parent)
 */
export function getRootSession(session) {
  let current = session;
  while (current.parentSessionId) {
    const parent = sessions.getById(current.parentSessionId);
    if (!parent) break;
    current = parent;
  }
  return current;
}

/**
 * Render a template prompt with parent session and root session context
 * @param {string} templatePrompt - The Liquid template string
 * @param {{ parentSession: Object, parentSummary: Object|null, rootSession: Object, rootSummary: Object|null }} sessionContext - Session context objects
 * @returns {Promise<string>} The rendered prompt
 */
export async function renderTemplatePrompt(templatePrompt, sessionContext) {
  const { parentSession, parentSummary, rootSession, rootSummary } = sessionContext;
  const context = {
    parentSession: {
      id: parentSession.id,
      name: parentSession.name,
      status: parentSession.status,
      summary: parentSummary?.fullSummary || parentSummary?.shortSummary || 'No summary available',
      shortSummary: parentSummary?.shortSummary || 'No summary available',
      fullSummary: parentSummary?.fullSummary || 'No summary available',
      keyActions: parentSummary?.keyActions || [],
      filesModified: parentSummary?.filesModified || [],
      outcome: parentSummary?.outcome || parentSession.status,
    },
    rootSession: {
      id: rootSession.id,
      name: rootSession.name,
      status: rootSession.status,
      summary: rootSummary?.fullSummary || rootSummary?.shortSummary || 'No summary available',
      shortSummary: rootSummary?.shortSummary || 'No summary available',
      fullSummary: rootSummary?.fullSummary || 'No summary available',
      keyActions: rootSummary?.keyActions || [],
      filesModified: rootSummary?.filesModified || [],
      outcome: rootSummary?.outcome || rootSession.status,
    },
  };

  return liquid.parseAndRender(templatePrompt, context);
}

/**
 * Derive session settings from template and root session.
 * Template values take precedence if set, otherwise inherit from root.
 */
function deriveSessionSettings(template, rootSession) {
  return {
    thinkingEnabled: template.thinkingEnabled !== null ? template.thinkingEnabled : rootSession.thinkingEnabled,
    gitBranch: template.gitBranch || rootSession.gitBranch,
    gitMode: template.gitMode || null,
    model: template.model !== null ? template.model : rootSession.model,
    mode: template.mode !== null ? template.mode : rootSession.mode,
    effortLevel: template.effortLevel !== null ? template.effortLevel : rootSession.effortLevel,
    // Inherit rescheduling settings from root session
    autoRescheduleEnabled: rootSession.autoRescheduleEnabled,
    rescheduleOnTokenLimit: rootSession.rescheduleOnTokenLimit,
    rescheduleOnServiceError: rootSession.rescheduleOnServiceError,
    rescheduleDelayMinutes: rootSession.rescheduleDelayMinutes,
    rescheduleAtTokenCount: rootSession.rescheduleAtTokenCount,
    maxRescheduleCount: rootSession.maxRescheduleCount,
    maxTotalTokens: rootSession.maxTotalTokens,
  };
}

/**
 * Check if a session should trigger its next template and do so
 * Called when a session completes (status changes to completed, error, or stopped)
 * @param {string} sessionId - The session that just completed
 */
export async function checkAndTriggerNextTemplate(sessionId) {
  const session = sessions.getById(sessionId);
  if (!session) {
    console.warn(`Template trigger: Session ${sessionId} not found`);
    return;
  }

  // Only trigger if session has a next template configured
  if (!session.nextTemplateId) {
    return;
  }

  const template = sessionTemplates.getById(session.nextTemplateId);
  if (!template) {
    console.warn(`Template trigger: Template ${session.nextTemplateId} not found for session ${sessionId}`);
    return;
  }

  const project = projects.getById(session.projectId);
  if (!project) {
    console.warn(`Template trigger: Project ${session.projectId} not found for session ${sessionId}`);
    return;
  }

  console.log(`Template trigger: Triggering template "${template.name}" after session "${session.name}"`);

  try {
    // Get the parent session's summary for the template context
    const parentSummary = sessionSummaries.getBySessionId(sessionId);

    // Get the root session and its summary
    const rootSession = getRootSession(session);
    const rootSummary = sessionSummaries.getBySessionId(rootSession.id);

    // Render the template prompt with parent and root session context
    const renderedPrompt = await renderTemplatePrompt(template.prompt, { parentSession: session, parentSummary, rootSession, rootSummary });
    const settings = deriveSessionSettings(template, rootSession);

    // Generate a name for the new session
    const newSessionName = `${template.name} (from: ${session.name})`;

    // Create the new session
    const newSession = sessions.create(
      session.projectId,
      newSessionName,
      renderedPrompt,
      {
        mode: settings.mode,
        thinkingEnabled: settings.thinkingEnabled,
        gitBranch: settings.gitBranch,
        parentSessionId: null, // Will be set below
        status: 'starting',
        model: settings.model,
        effortLevel: settings.effortLevel,
      }
    );

    // Set the parent session reference and inherit the template's next template for chaining
    sessions.update(newSession.id, {
      parentSessionId: session.id,
      nextTemplateId: template.nextTemplateId || null,
      autoRescheduleEnabled: settings.autoRescheduleEnabled,
      rescheduleOnTokenLimit: settings.rescheduleOnTokenLimit,
      rescheduleOnServiceError: settings.rescheduleOnServiceError,
      rescheduleDelayMinutes: settings.rescheduleDelayMinutes,
      rescheduleAtTokenCount: settings.rescheduleAtTokenCount,
      maxRescheduleCount: settings.maxRescheduleCount,
      maxTotalTokens: settings.maxTotalTokens,
    });

    // Determine working directory: inherit from parent if it has a worktree
    let workingDirectory;
    let gitWorktree = null;

    if (session.gitWorktree) {
      // Parent is in a worktree - child should run in the same worktree
      workingDirectory = session.gitWorktree;
      gitWorktree = session.gitWorktree;
      console.log(`Template trigger: Inheriting parent worktree: ${gitWorktree}`);
    } else {
      // Parent is not in a worktree - set up git environment normally
      const gitSetup = await setupGitForSession({
        projectDir: project.workingDirectory,
        gitMode: settings.gitMode,
        gitBranch: settings.gitBranch,
        sessionId: newSession.id,
      });
      workingDirectory = gitSetup.workingDirectory;
      gitWorktree = gitSetup.gitWorktree;
    }

    // Update session with worktree path if set
    if (gitWorktree) {
      sessions.update(newSession.id, { gitWorktree });
    }

    // Get the fully updated session and broadcast to project subscribers
    const updatedSession = sessions.getById(newSession.id);
    broadcastToProject(session.projectId, WS_MESSAGE_TYPES.SESSION_CREATED, {
      projectId: session.projectId,
      session: updatedSession,
    });

    // Start the new session (non-blocking)
    runSession(newSession.id, renderedPrompt, workingDirectory, { systemPrompt: project.systemPrompt, model: settings.model }).catch((error) => {
      console.error(`Template trigger: Error running session ${newSession.id}:`, error);
      const errorSession = sessions.update(newSession.id, { status: 'error', error: error.message });
      // Broadcast error status to project subscribers for session list updates
      broadcastToProject(session.projectId, WS_MESSAGE_TYPES.SESSION_UPDATED, {
        projectId: session.projectId,
        sessionId: newSession.id,
        session: errorSession,
      });
    });

    console.log(`Template trigger: Created and started session ${newSession.id}`);
  } catch (error) {
    console.error(`Template trigger: Failed to trigger template for session ${sessionId}:`, error);
  }
}

/**
 * Sessions API resource mixin
 * Adds session-related methods to ApiClient
 * @param {import('../ApiClient.js').ApiClient} ApiClient
 */
export function SessionsApi(ApiClient) {
  Object.assign(ApiClient.prototype, {
    /**
     * Get all active/waiting sessions across all projects
     * @returns {Promise<Array>}
     */
    async getActiveSessions() {
      return this._get('/sessions');
    },

    /**
     * Get all scheduled sessions (optionally filtered by project)
     * @param {string|null} projectId - Optional project ID to filter by
     * @returns {Promise<Array>}
     */
    async getScheduledSessions(projectId = null) {
      return this._get(this._buildQueryPath('/sessions/scheduled', {
        projectId: projectId || undefined,
      }));
    },

    /**
     * Get all sessions for a project
     * @param {string} projectId - Project ID
     * @param {boolean|null} archived - Filter by archived status (null = all, true = archived only, false = non-archived only)
     * @param {string|null} starred - Filter by starred status (null = all, 'starred' = starred only, 'unstarred' = unstarred only)
     * @param {Object} paginationOptions - Pagination options
     * @param {number|null} paginationOptions.limit - Number of sessions to fetch (null = all)
     * @param {number} paginationOptions.offset - Offset for pagination (default: 0)
     * @returns {Promise<Array|{sessions: Array, pagination: Object}>} Array when no pagination, object with pagination metadata when limit is specified
     */
    async getProjectSessions(projectId, archived = null, starred = null, { limit = null, offset = 0 } = {}) {
      const params = {};
      if (archived !== null) {
        params.archived = archived;
      }
      if (starred === 'starred') {
        params.starred = true;
      } else if (starred === 'unstarred') {
        params.starred = false;
      }
      if (limit !== null) {
        params.limit = limit;
        params.offset = offset;
      }
      return this._get(this._buildQueryPath(`/projects/${projectId}/sessions`, params));
    },

    /**
     * Create a new session
     * @param {string} projectId - Project ID
     * @param {Object} data - Session data (may include files array and startImmediately flag)
     * @returns {Promise<Object>}
     */
    async createSession(projectId, data) {
      const { files, ...jsonData } = data;

      // Use FormData if files are attached, otherwise JSON
      if (files && files.length > 0) {
        const formData = new FormData();
        formData.append('prompt', jsonData.prompt);
        if (jsonData.name !== undefined) formData.append('name', jsonData.name);
        if (jsonData.mode !== undefined) formData.append('mode', jsonData.mode);
        if (jsonData.model !== undefined) formData.append('model', jsonData.model);
        if (jsonData.thinkingEnabled !== undefined) {
          formData.append('thinkingEnabled', String(jsonData.thinkingEnabled));
        }
        if (jsonData.effortLevel !== undefined) {
          formData.append('effortLevel', jsonData.effortLevel);
        }
        if (jsonData.startImmediately !== undefined) {
          formData.append('startImmediately', String(jsonData.startImmediately));
        }
        if (jsonData.gitBranch !== undefined) formData.append('gitBranch', jsonData.gitBranch);
        if (jsonData.gitMode !== undefined) formData.append('gitMode', jsonData.gitMode);
        if (jsonData.templateId !== undefined) formData.append('templateId', jsonData.templateId);

        for (const file of files) {
          formData.append('files', file);
        }

        return this._uploadFormData(`/projects/${projectId}/sessions`, formData);
      }

      return this._post(`/projects/${projectId}/sessions`, jsonData);
    },

    /**
     * Get a session by ID
     * @param {string} id - Session ID
     * @returns {Promise<Object>}
     */
    async getSession(id) {
      return this._get(`/sessions/${id}`);
    },

    /**
     * Get all messages for a session
     * @param {string} id - Session ID
     * @returns {Promise<Array>}
     */
    async getSessionMessages(id) {
      return this._get(`/sessions/${id}/messages`);
    },

    /**
     * Get work logs for a session (grouped by message ID)
     * @param {string} sessionId - Session ID
     * @returns {Promise<Object>} Work logs grouped by message ID
     */
    async getSessionWorkLogs(sessionId) {
      return this._get(`/sessions/${sessionId}/work-logs`);
    },

    /**
     * Send a message to a session
     * @param {string} sessionId - Session ID
     * @param {string} content - Message content
     * @param {Array} files - Optional array of files to attach
     * @param {string|null} model - Model to use for this message
     * @returns {Promise<Object>}
     */
    async sendMessage(sessionId, content, files = [], model = null) {
      // [MODEL AUDIT] Log model in API request
      console.log(`[MODEL AUDIT - ApiClient] sendMessage called with model: "${model}"`);

      // Use FormData if files are attached, otherwise JSON
      if (files && files.length > 0) {
        const formData = new FormData();
        formData.append('content', content);
        if (model) {
          formData.append('model', model);
        }

        for (const file of files) {
          formData.append('files', file);
        }

        return this._uploadFormData(`/sessions/${sessionId}/message`, formData);
      }

      return this._post(`/sessions/${sessionId}/message`, { content, model });
    },

    /**
     * Stop a session
     * @param {string} id - Session ID
     * @returns {Promise<Object>}
     */
    async stopSession(id) {
      return this._post(`/sessions/${id}/stop`);
    },

    /**
     * Get git changes for a session
     * @param {string} sessionId - Session ID
     * @param {string} compareMode - 'local' (default) or 'branch'
     * @param {string|null} branch - Branch to compare against (only used if compareMode is 'branch')
     * @returns {Promise<{staged: string, unstaged: string, untracked: string}>}
     */
    async getSessionChanges(sessionId, compareMode = 'local', branch = null) {
      const params = {};
      if (compareMode === 'branch') {
        params.compareMode = 'branch';
        if (branch) {
          params.branch = branch;
        }
      }
      return this._get(this._buildQueryPath(`/sessions/${sessionId}/changes`, params));
    },

    /**
     * Get the default branch for a session (for branch comparison)
     * @param {string} sessionId
     * @returns {Promise<{branch: string}>}
     */
    async getSessionDefaultBranch(sessionId) {
      return this._get(`/sessions/${sessionId}/default-branch`);
    },

    /**
     * Get count of files modified compared to the default branch
     * @param {string} sessionId - Session ID
     * @returns {Promise<{count: number}>}
     */
    async getSessionFilesCount(sessionId) {
      return this._get(`/sessions/${sessionId}/files-count`);
    },

    /**
     * Get a file from the session's working directory (for displaying images in diffs)
     * @param {string} sessionId - Session ID
     * @param {string} filePath - Relative path to file
     * @returns {Promise<{data: string, mimeType: string, filename: string}>}
     */
    async getSessionFile(sessionId, filePath) {
      return this._get(`/sessions/${sessionId}/file?path=${encodeURIComponent(filePath)}`);
    },

    /**
     * Restart a completed or errored session
     * @param {string} id - Session ID
     * @returns {Promise<Object>}
     */
    async restartSession(id) {
      return this._post(`/sessions/${id}/restart`);
    },

    /**
     * Start a draft session (waiting status with no assistant messages)
     * @param {string} id - Session ID
     * @param {string|undefined} prompt - Optional updated prompt to use when starting
     * @param {string|undefined} model - Optional model override
     * @returns {Promise<Object>}
     */
    async startSession(id, prompt, model) {
      const data = {};
      if (prompt !== undefined) data.prompt = prompt;
      if (model !== undefined) data.model = model;
      return this._post(`/sessions/${id}/start`,
        Object.keys(data).length > 0 ? data : undefined);
    },

    /**
     * Update the initial prompt for a draft session
     * @param {string} id - Session ID
     * @param {string} prompt - The new prompt
     * @returns {Promise<Object>}
     */
    async updateSessionInitialPrompt(id, prompt) {
      return this._put(`/sessions/${id}/initial-prompt`, { prompt });
    },

    /**
     * Update session settings
     * @param {string} id - Session ID
     * @param {Object} data - Update data (e.g., { thinkingEnabled: true })
     * @returns {Promise<Object>}
     */
    async updateSession(id, data) {
      return this._patch(`/sessions/${id}`, data);
    },

    /**
     * Update the pending prompt for a session (auto-save input field)
     * @param {string} id - Session ID
     * @param {string|null} pendingPrompt - The pending prompt (or null to clear)
     * @returns {Promise<Object>}
     */
    async updateSessionPendingPrompt(id, pendingPrompt) {
      return this._patch(`/sessions/${id}/pending-prompt`, { pendingPrompt });
    },

    /**
     * Delete a session
     * @param {string} id - Session ID
     * @returns {Promise<void>}
     */
    async deleteSession(id) {
      return this._delete(`/sessions/${id}`);
    },

    /**
     * Archive a session
     * @param {string} id - Session ID
     * @returns {Promise<Object>}
     */
    async archiveSession(id) {
      return this._post(`/sessions/${id}/archive`);
    },

    /**
     * Unarchive a session
     * @param {string} id - Session ID
     * @returns {Promise<Object>}
     */
    async unarchiveSession(id) {
      return this._post(`/sessions/${id}/unarchive`);
    },

    /**
     * Toggle star status for a session
     * @param {string} id - Session ID
     * @returns {Promise<Object>}
     */
    async toggleSessionStar(id) {
      return this._post(`/sessions/${id}/star`);
    },

    /**
     * Duplicate a session (clone with all data)
     * @param {string} id - Session ID to duplicate
     * @param {Object} options - Duplication options
     * @param {string} [options.name] - Custom name for duplicated session
     * @param {string} [options.gitMode] - Git mode (none|branch|worktree)
     * @param {string} [options.gitBranch] - Git branch name (if gitMode is branch)
     * @returns {Promise<Object>}
     */
    async duplicateSession(id, options = {}) {
      return this._post(`/sessions/${id}/duplicate`, options);
    },

    /**
     * Schedule a follow-up for an existing session
     * @param {string} id - Session ID
     * @param {Object} data - Scheduling data
     * @returns {Promise<Object>}
     */
    async scheduleSession(id, data) {
      return this._post(`/sessions/${id}/schedule`, data);
    },
  });
}

