import {
  useInjectedSessionsStore,
  useInjectedTodosStore,
  SESSIONS_STORE_KEY,
  TODOS_STORE_KEY,
} from './useOverlayStore.js';
import { useSessionsStore } from '../stores/sessions.js';
import { useTodosStore } from '../stores/todos.js';

/**
 * Helper to call a composable inside a component setup context.
 * Optionally provides values via Vue's provide/inject.
 */
function withSetup(composable, provideMap = {}) {
  let result;
  const pinia = createPinia();
  setActivePinia(pinia);

  const Wrapper = defineComponent({
    setup() {
      Object.entries(provideMap).forEach(([key, val]) => {
        // provideMap keys are the actual Symbol keys
        provide(key, val);
      });
      result = composable();
      return () => h('div');
    },
  });
  mount(Wrapper, { global: { plugins: [pinia] } });
  return result;
}

/**
 * Helper that wraps composable in a child component with a parent provider.
 */
function withProviderAndChild(composable, provideKey, provideValue) {
  let result;
  const pinia = createPinia();
  setActivePinia(pinia);

  const Child = defineComponent({
    setup() {
      result = composable();
      return () => h('div');
    },
  });

  const Parent = defineComponent({
    setup() {
      provide(provideKey, provideValue);
      return () => h(Child);
    },
  });

  mount(Parent, { global: { plugins: [pinia] } });
  return result;
}

describe('useOverlayStore', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  describe('Symbol keys', () => {
    it('SESSIONS_STORE_KEY and TODOS_STORE_KEY are unique symbols', () => {
      expect(typeof SESSIONS_STORE_KEY).toBe('symbol');
      expect(typeof TODOS_STORE_KEY).toBe('symbol');
      expect(SESSIONS_STORE_KEY).not.toBe(TODOS_STORE_KEY);
    });
  });

  describe('useInjectedSessionsStore', () => {
    it('returns global singleton when no provider exists', () => {
      const pinia = createPinia();
      setActivePinia(pinia);

      const injectedStore = withSetup(useInjectedSessionsStore);
      const globalStore = useSessionsStore();

      expect(injectedStore.$id).toBe(globalStore.$id);
    });

    it('returns provided instance when provider exists', () => {
      const mockStore = { $id: 'mock-sessions', isMock: true };

      const injectedStore = withProviderAndChild(
        useInjectedSessionsStore,
        SESSIONS_STORE_KEY,
        mockStore,
      );

      expect(injectedStore).toBe(mockStore);
      expect(injectedStore.isMock).toBe(true);
    });
  });

  describe('useInjectedTodosStore', () => {
    it('returns global singleton when no provider exists', () => {
      const pinia = createPinia();
      setActivePinia(pinia);

      const injectedStore = withSetup(useInjectedTodosStore);
      const globalStore = useTodosStore();

      expect(injectedStore.$id).toBe(globalStore.$id);
    });

    it('returns provided instance when provider exists', () => {
      const mockStore = { $id: 'mock-todos', isMock: true };

      const injectedStore = withProviderAndChild(
        useInjectedTodosStore,
        TODOS_STORE_KEY,
        mockStore,
      );

      expect(injectedStore).toBe(mockStore);
      expect(injectedStore.isMock).toBe(true);
    });
  });
});

import { onUnmounted } from 'vue';
import { WS_MESSAGE_TYPES } from '@circuschief/shared';
import { useWebSocket } from './useWebSocket.js';

// Track active project subscriptions for re-subscription on reconnect
export const projectSubscriptionIds = new Set();

/**
 * Subscribe to project updates (session list changes)
 * @param {string} projectId
 */
export function useProjectSubscription(projectId) {
  const { send, on, off } = useWebSocket();

  const subscribe = () => {
    projectSubscriptionIds.add(projectId);
    send(WS_MESSAGE_TYPES.SUBSCRIBE_PROJECT, { projectId });
  };

  const unsubscribe = () => {
    projectSubscriptionIds.delete(projectId);
    send(WS_MESSAGE_TYPES.UNSUBSCRIBE_PROJECT, { projectId });
  };

  const onSessionCreated = (callback) => {
    const handler = (msg) => {
      if (msg.projectId === projectId) {
        callback(msg.session);
      }
    };
    on(WS_MESSAGE_TYPES.SESSION_CREATED, handler);
    return () => off(WS_MESSAGE_TYPES.SESSION_CREATED, handler);
  };

  const onSessionUpdated = (callback) => {
    const handler = (msg) => {
      if (msg.projectId === projectId) {
        callback(msg.session);
      }
    };
    on(WS_MESSAGE_TYPES.SESSION_UPDATED, handler);
    return () => off(WS_MESSAGE_TYPES.SESSION_UPDATED, handler);
  };

  const onSessionDeleted = (callback) => {
    const handler = (msg) => {
      if (msg.projectId === projectId) {
        callback(msg.sessionId);
      }
    };
    on(WS_MESSAGE_TYPES.SESSION_DELETED, handler);
    return () => off(WS_MESSAGE_TYPES.SESSION_DELETED, handler);
  };

  const onSessionSummaryUpdated = (callback) => {
    const handler = (msg) => {
      if (msg.projectId === projectId) {
        callback(msg.sessionId, msg.summary);
      }
    };
    on(WS_MESSAGE_TYPES.SESSION_SUMMARY_UPDATED, handler);
    return () => off(WS_MESSAGE_TYPES.SESSION_SUMMARY_UPDATED, handler);
  };

  // Command run handlers for real-time status icon updates on session lists
  const onCommandRunOutput = (callback) => {
    const handler = (msg) => {
      if (msg.projectId === projectId) {
        callback(msg.runId, msg.sessionId, msg.buttonId, msg.output);
      }
    };
    on(WS_MESSAGE_TYPES.COMMAND_RUN_OUTPUT, handler);
    return () => off(WS_MESSAGE_TYPES.COMMAND_RUN_OUTPUT, handler);
  };

  const onCommandRunComplete = (callback) => {
    const handler = (msg) => {
      if (msg.projectId === projectId) {
        callback({
          runId: msg.runId,
          sessionId: msg.sessionId,
          buttonId: msg.buttonId,
          exitCode: msg.exitCode,
          output: msg.output,
          status: msg.status,
        });
      }
    };
    on(WS_MESSAGE_TYPES.COMMAND_RUN_COMPLETE, handler);
    return () => off(WS_MESSAGE_TYPES.COMMAND_RUN_COMPLETE, handler);
  };

  const onCommandRunError = (callback) => {
    const handler = (msg) => {
      if (msg.projectId === projectId) {
        callback(msg.runId, msg.sessionId, msg.buttonId, msg.error);
      }
    };
    on(WS_MESSAGE_TYPES.COMMAND_RUN_ERROR, handler);
    return () => off(WS_MESSAGE_TYPES.COMMAND_RUN_ERROR, handler);
  };

  const onCommandRunDeleted = (callback) => {
    const handler = (msg) => {
      if (msg.projectId === projectId) {
        callback(msg.runId, msg.sessionId, msg.buttonId);
      }
    };
    on(WS_MESSAGE_TYPES.COMMAND_RUN_DELETED, handler);
    return () => off(WS_MESSAGE_TYPES.COMMAND_RUN_DELETED, handler);
  };

  // Kanban event handlers
  const onKanbanBoardUpdated = (callback) => {
    const handler = (msg) => {
      if (msg.projectId === projectId) {
        callback(msg.board);
      }
    };
    on(WS_MESSAGE_TYPES.KANBAN_BOARD_UPDATED, handler);
    return () => off(WS_MESSAGE_TYPES.KANBAN_BOARD_UPDATED, handler);
  };

  const onKanbanCardMoved = (callback) => {
    const handler = (msg) => {
      if (msg.projectId === projectId) {
        callback(msg.cardId, msg.fromLaneId, msg.toLaneId, msg.card);
      }
    };
    on(WS_MESSAGE_TYPES.KANBAN_CARD_MOVED, handler);
    return () => off(WS_MESSAGE_TYPES.KANBAN_CARD_MOVED, handler);
  };

  const onKanbanCardAdded = (callback) => {
    const handler = (msg) => {
      if (msg.projectId === projectId) {
        callback(msg.card, msg.laneId);
      }
    };
    on(WS_MESSAGE_TYPES.KANBAN_CARD_ADDED, handler);
    return () => off(WS_MESSAGE_TYPES.KANBAN_CARD_ADDED, handler);
  };

  const onKanbanCardRemoved = (callback) => {
    const handler = (msg) => {
      if (msg.projectId === projectId) {
        callback(msg.cardId, msg.laneId);
      }
    };
    on(WS_MESSAGE_TYPES.KANBAN_CARD_REMOVED, handler);
    return () => off(WS_MESSAGE_TYPES.KANBAN_CARD_REMOVED, handler);
  };

  // Auto-cleanup on unmount
  onUnmounted(() => {
    unsubscribe();
  });

  return {
    subscribe,
    unsubscribe,
    onSessionCreated,
    onSessionUpdated,
    onSessionDeleted,
    onSessionSummaryUpdated,
    onCommandRunOutput,
    onCommandRunComplete,
    onCommandRunError,
    onCommandRunDeleted,
    onKanbanBoardUpdated,
    onKanbanCardMoved,
    onKanbanCardAdded,
    onKanbanCardRemoved,
  };
}

import { onUnmounted } from 'vue';
import { WS_MESSAGE_TYPES } from '@circuschief/shared';
import { useWebSocket } from './useWebSocket.js';

// Reference counting for session subscriptions
// Prevents premature unsubscription when multiple components use the same session
const sessionSubscriptionCounts = new Map();

/**
 * Subscribe to session updates
 * @param {string} sessionId
 */
export function useSessionSubscription(sessionId) {
  const { send, on, off, clearSessionBuffer } = useWebSocket();

  // Track whether THIS instance called subscribe
  let thisInstanceSubscribed = false;

  const subscribe = () => {
    if (thisInstanceSubscribed) return; // Already subscribed from this instance
    thisInstanceSubscribed = true;

    const count = sessionSubscriptionCounts.get(sessionId) || 0;
    sessionSubscriptionCounts.set(sessionId, count + 1);
    // Only send subscribe message on first subscription
    if (count === 0) {
      send(WS_MESSAGE_TYPES.SUBSCRIBE_SESSION, { sessionId });
    }
  };

  const unsubscribe = () => {
    if (!thisInstanceSubscribed) return; // Never subscribed, don't unsubscribe
    thisInstanceSubscribed = false;

    const count = sessionSubscriptionCounts.get(sessionId) || 0;
    if (count <= 1) {
      // Last subscriber - actually unsubscribe
      sessionSubscriptionCounts.delete(sessionId);
      send(WS_MESSAGE_TYPES.UNSUBSCRIBE_SESSION, { sessionId });
      // Clear any buffered messages for this session
      clearSessionBuffer(sessionId);
    } else {
      // Decrement count but don't unsubscribe yet
      sessionSubscriptionCounts.set(sessionId, count - 1);
    }
  };

  const onStatus = (callback) => {
    const handler = (msg) => {
      if (msg.sessionId === sessionId) {
        callback(msg.status);
      }
    };
    on(WS_MESSAGE_TYPES.SESSION_STATUS, handler);
    return () => off(WS_MESSAGE_TYPES.SESSION_STATUS, handler);
  };

  const onMessage = (callback) => {
    const handler = (msg) => {
      // Filter by sessionId to avoid cross-session interference
      if (msg.message?.sessionId === sessionId) {
        callback(msg.message);
      }
    };
    on(WS_MESSAGE_TYPES.SESSION_MESSAGE, handler);
    return () => off(WS_MESSAGE_TYPES.SESSION_MESSAGE, handler);
  };

  const onError = (callback) => {
    const handler = (msg) => {
      if (msg.sessionId === sessionId) {
        callback(msg.error);
      }
    };
    on(WS_MESSAGE_TYPES.SESSION_ERROR, handler);
    return () => off(WS_MESSAGE_TYPES.SESSION_ERROR, handler);
  };

  const onCanvasAdd = (callback) => {
    const handler = (msg) => {
      if (msg.item?.sessionId === sessionId) {
        callback(msg.item);
      }
    };
    on(WS_MESSAGE_TYPES.CANVAS_ADD, handler);
    return () => off(WS_MESSAGE_TYPES.CANVAS_ADD, handler);
  };

  const onCanvasRemove = (callback) => {
    const handler = (msg) => {
      if (msg.sessionId === sessionId) {
        callback(msg.itemId);
      }
    };
    on(WS_MESSAGE_TYPES.CANVAS_REMOVE, handler);
    return () => off(WS_MESSAGE_TYPES.CANVAS_REMOVE, handler);
  };

  const onCanvasUpdate = (callback) => {
    const handler = (msg) => {
      if (msg.item?.sessionId === sessionId) {
        callback(msg.item);
      }
    };
    on(WS_MESSAGE_TYPES.CANVAS_UPDATE, handler);
    return () => off(WS_MESSAGE_TYPES.CANVAS_UPDATE, handler);
  };

  const onPartial = (callback) => {
    const handler = (msg) => {
      if (msg.sessionId === sessionId) {
        callback(msg.text);
      }
    };
    on(WS_MESSAGE_TYPES.SESSION_PARTIAL, handler);
    return () => off(WS_MESSAGE_TYPES.SESSION_PARTIAL, handler);
  };

  const onTodosUpdate = (callback) => {
    const handler = (msg) => {
      if (msg.sessionId === sessionId) {
        callback(msg.todos, msg.conversationId);
      }
    };
    on(WS_MESSAGE_TYPES.TODOS_UPDATE, handler);
    return () => off(WS_MESSAGE_TYPES.TODOS_UPDATE, handler);
  };

  const onWorkLog = (callback) => {
    const handler = (msg) => {
      if (msg.sessionId === sessionId && msg.log) {
        callback(msg.log);
      }
    };
    on(WS_MESSAGE_TYPES.SESSION_WORK_LOG, handler);
    return () => off(WS_MESSAGE_TYPES.SESSION_WORK_LOG, handler);
  };

  const onWorkLogsAssociated = (callback) => {
    const handler = (msg) => {
      if (msg.sessionId === sessionId) {
        callback(msg.messageId);
      }
    };
    on(WS_MESSAGE_TYPES.SESSION_WORK_LOGS_ASSOCIATED, handler);
    return () => off(WS_MESSAGE_TYPES.SESSION_WORK_LOGS_ASSOCIATED, handler);
  };

  const onThinkingPartial = (callback) => {
    const handler = (msg) => {
      if (msg.sessionId === sessionId) {
        callback(msg.thinking);
      }
    };
    on(WS_MESSAGE_TYPES.SESSION_THINKING_PARTIAL, handler);
    return () => off(WS_MESSAGE_TYPES.SESSION_THINKING_PARTIAL, handler);
  };

  const onSummaryUpdate = (callback) => {
    const handler = (msg) => {
      if (msg.sessionId === sessionId) {
        callback(msg.summary);
      }
    };
    on(WS_MESSAGE_TYPES.SESSION_SUMMARY_UPDATED, handler);
    return () => off(WS_MESSAGE_TYPES.SESSION_SUMMARY_UPDATED, handler);
  };

  const onSummaryGenerating = (callback) => {
    const handler = (msg) => {
      if (msg.sessionId === sessionId) {
        callback(msg.generating);
      }
    };
    on(WS_MESSAGE_TYPES.SESSION_SUMMARY_GENERATING, handler);
    return () => off(WS_MESSAGE_TYPES.SESSION_SUMMARY_GENERATING, handler);
  };

  const onSessionUpdate = (callback) => {
    const handler = (msg) => {
      if (msg.sessionId === sessionId) {
        callback(msg.session);
      }
    };
    on(WS_MESSAGE_TYPES.SESSION_UPDATED, handler);
    return () => off(WS_MESSAGE_TYPES.SESSION_UPDATED, handler);
  };

  const onConversationCreated = (callback) => {
    const handler = (msg) => {
      if (msg.sessionId === sessionId) {
        callback(msg.conversation);
      }
    };
    on(WS_MESSAGE_TYPES.CONVERSATION_CREATED, handler);
    return () => off(WS_MESSAGE_TYPES.CONVERSATION_CREATED, handler);
  };

  const onConversationUpdated = (callback) => {
    const handler = (msg) => {
      if (msg.sessionId === sessionId) {
        callback(msg.conversation);
      }
    };
    on(WS_MESSAGE_TYPES.CONVERSATION_UPDATED, handler);
    return () => off(WS_MESSAGE_TYPES.CONVERSATION_UPDATED, handler);
  };

  const onConversationDeleted = (callback) => {
    const handler = (msg) => {
      if (msg.sessionId === sessionId) {
        callback(msg.conversationId, msg.newActiveConversation);
      }
    };
    on(WS_MESSAGE_TYPES.CONVERSATION_DELETED, handler);
    return () => off(WS_MESSAGE_TYPES.CONVERSATION_DELETED, handler);
  };

  const onUsageUpdate = (callback) => {
    const handler = (msg) => {
      if (msg.sessionId === sessionId) {
        callback(msg);
      }
    };
    // Pass sessionId to on() so only this session's buffered messages are replayed
    on(WS_MESSAGE_TYPES.SESSION_USAGE_UPDATE, handler, sessionId);
    return () => off(WS_MESSAGE_TYPES.SESSION_USAGE_UPDATE, handler);
  };

  const onCommandOutput = (callback) => {
    const handler = (msg) => {
      if (msg.sessionId === sessionId) {
        callback(msg.runId, msg.buttonId, msg.output);
      }
    };
    on(WS_MESSAGE_TYPES.COMMAND_RUN_OUTPUT, handler);
    return () => off(WS_MESSAGE_TYPES.COMMAND_RUN_OUTPUT, handler);
  };

  const onCommandComplete = (callback) => {
    const handler = (msg) => {
      if (msg.sessionId === sessionId) {
        callback(msg.runId, msg.buttonId, msg.exitCode, msg.output);
      }
    };
    on(WS_MESSAGE_TYPES.COMMAND_RUN_COMPLETE, handler);
    return () => off(WS_MESSAGE_TYPES.COMMAND_RUN_COMPLETE, handler);
  };

  const onCommandError = (callback) => {
    const handler = (msg) => {
      if (msg.sessionId === sessionId) {
        callback(msg.runId, msg.buttonId, msg.error || msg.message);
      }
    };
    on(WS_MESSAGE_TYPES.COMMAND_RUN_ERROR, handler);
    return () => off(WS_MESSAGE_TYPES.COMMAND_RUN_ERROR, handler);
  };

  const onCommandRunDeleted = (callback) => {
    const handler = (msg) => {
      if (msg.sessionId === sessionId) {
        callback(msg.runId, msg.buttonId);
      }
    };
    on(WS_MESSAGE_TYPES.COMMAND_RUN_DELETED, handler);
    return () => off(WS_MESSAGE_TYPES.COMMAND_RUN_DELETED, handler);
  };

  const onChangesUpdate = (callback) => {
    const handler = (msg) => {
      if (msg.sessionId === sessionId) {
        callback(msg.changeCount, msg.hasChanges);
      }
    };
    on(WS_MESSAGE_TYPES.CHANGES_UPDATE, handler);
    return () => off(WS_MESSAGE_TYPES.CHANGES_UPDATE, handler);
  };

  // Auto-cleanup on unmount
  onUnmounted(() => {
    unsubscribe();
  });

  return {
    subscribe,
    unsubscribe,
    onStatus,
    onMessage,
    onPartial,
    onError,
    onCanvasAdd,
    onCanvasRemove,
    onCanvasUpdate,
    onTodosUpdate,
    onWorkLog,
    onWorkLogsAssociated,
    onThinkingPartial,
    onSummaryUpdate,
    onSummaryGenerating,
    onSessionUpdate,
    onConversationCreated,
    onConversationUpdated,
    onConversationDeleted,
    onUsageUpdate,
    onCommandOutput,
    onCommandComplete,
    onCommandError,
    onCommandRunDeleted,
    onChangesUpdate,
  };
}

// Export for use in useWebSocket.js
export { sessionSubscriptionCounts };

import { api } from '../../composables/useApi.js';

/**
 * Update a session in a list, or add it if not found.
 * @param {Array} listInput - The list to update
 * @param {Object} sessionData - The session data
 * @param {boolean} addIfMissing - Whether to add the session if not found
 */
function updateSessionInList(listInput, sessionData, addIfMissing = false) {
  const list = listInput;
  const index = list.findIndex((s) => s.id === sessionData.id);
  if (index !== -1) {
    list[index] = { ...list[index], ...sessionData };
  } else if (addIfMissing) {
    list.unshift(sessionData);
  }
}

/**
 * Move a session between lists (e.g., archive/unarchive).
 * @param {Array} sourceList - The list to remove from
 * @param {Array} targetList - The list to add to
 * @param {Object} sessionData - The session data
 */
function moveSessionBetweenLists(sourceList, targetList, sessionData) {
  const existingSession = sourceList.find((s) => s.id === sessionData.id);
  const merged = existingSession ? { ...existingSession, ...sessionData } : sessionData;
  updateSessionInList(targetList, merged, true);
  return sourceList.filter((s) => s.id !== sessionData.id);
}

/**
 * Session CRUD and lifecycle actions for the sessions store.
 * These are spread directly into the Pinia store actions, so `this` refers to the store instance.
 */
export const sessionActions = {
  async fetchActiveSessions(showLoading = true) {
    if (showLoading) this.loading = true;
    this.error = null;
    try { this.activeSessions = await api.getActiveSessions(); }
    catch (err) { this.error = err.message; }
    finally { if (showLoading) this.loading = false; }
  },

  async fetchScheduledSessions(projectId = null) {
    this.loadingScheduled = true;
    this.error = null;
    try {
      const sessions = await api.getScheduledSessions(projectId);
      this.scheduledSessions = sessions.sort((a, b) => new Date(a.scheduledAt) - new Date(b.scheduledAt));
    } catch (err) {
      this.error = err.message;
      console.error('Failed to fetch scheduled sessions:', err);
    } finally { this.loadingScheduled = false; }
  },

  async fetchSessions(projectId) {
    this.loading = true;
    this.error = null;
    try { this.sessions = await api.getProjectSessions(projectId, false, null); }
    catch (err) { this.error = err.message; }
    finally { this.loading = false; }
  },

  async fetchArchivedSessions(projectId, { reset = true } = {}) {
    const PAGE_SIZE = 25;
    if (reset) { this.archivedSessions = []; this.archivedPagination.offset = 0; }
    this.archivedPagination.loading = true;
    this.error = null;
    try {
      const response = await api.getProjectSessions(
        projectId, true, this.starredFilter, { limit: PAGE_SIZE, offset: this.archivedPagination.offset }
      );
      this.archivedSessions = reset ? response.sessions : [...this.archivedSessions, ...response.sessions];
      this.archivedPagination = {
        total: response.pagination.total,
        offset: this.archivedPagination.offset + response.sessions.length,
        hasMore: response.pagination.hasMore, loading: false,
      };
    } catch (err) { this.error = err.message; this.archivedPagination.loading = false; }
  },

  async loadMoreArchivedSessions(projectId) {
    if (this.archivedPagination.hasMore && !this.archivedPagination.loading) {
      await this.fetchArchivedSessions(projectId, { reset: false });
    }
  },

  async fetchSession(id, showLoading = true) {
    if (showLoading) this.loading = true;
    this.error = null;
    try {
      const fetchedSession = await api.getSession(id);
      // Guard: only set currentSession if the user is still viewing this session.
      // This prevents stale in-flight requests (e.g., from polling that was active
      // for a previous session) from overwriting currentSession after navigation.
      if (this.viewedSessionId && this.viewedSessionId !== id) {
        // Session changed while we were fetching — discard this result for currentSession
        // but still update the session in list arrays below.
        const sessionIndex = this.sessions.findIndex((s) => s.id === id);
        if (sessionIndex !== -1) this.sessions[sessionIndex] = { ...this.sessions[sessionIndex], ...fetchedSession };
        return;
      }
      this.currentSession = fetchedSession;
      // Add the fetched session to the sessions array if not already present
      // This ensures getSessionById() can find it for computed properties like activeSessionName
      const existingIndex = this.sessions.findIndex((s) => s.id === id);
      if (existingIndex !== -1) {
        this.sessions[existingIndex] = fetchedSession;
      } else {
        this.sessions.push(fetchedSession);
      }
      if (this.currentSession?.parentSessionId) {
        let parentId = this.currentSession.parentSessionId;
        while (parentId) {
          const existingParent = this.sessions.find((s) => s.id === parentId);
          if (existingParent) { parentId = existingParent.parentSessionId; continue; }
          try {
            const parentSession = await api.getSession(parentId);
            this.sessions.push(parentSession);
            parentId = parentSession.parentSessionId;
          } catch (error) { console.error('Failed to fetch parent session:', error); break; }
        }
      }
      if (this.currentSession?.projectId) {
        try {
          const projectSessions = await api.getProjectSessions(this.currentSession.projectId);
          const childSessions = projectSessions.filter(s => s.parentSessionId === id);
          const newChildren = childSessions.filter(child => !this.sessions.find(s => s.id === child.id));
          this.sessions.push(...newChildren);
        } catch (error) { console.error('Failed to fetch child sessions:', error); }
      }
    } catch (err) { this.error = err.message; }
    finally { if (showLoading) this.loading = false; }
  },

  async createSession(projectId, data) {
    this.loading = true;
    this.error = null;
    try {
      const session = await api.createSession(projectId, data);
      this.sessions.unshift(session);
      return session;
    } catch (err) { this.error = err.message; throw err; }
    finally { this.loading = false; }
  },

  async sendMessage(sessionId, content, files = [], model = null) {
    this.error = null;
    try {
      await api.sendMessage(sessionId, content, files, model);
      this._updateSessionInAllLists(sessionId, { status: 'running' });
    } catch (err) { this.error = err.message; throw err; }
  },

  async stopSession(id) {
    this.error = null;
    try { await api.stopSession(id); this._updateSessionInAllLists(id, { status: 'stopped' }); }
    catch (err) { this.error = err.message; throw err; }
  },

  async restartSession(id) {
    this.error = null;
    try { await api.restartSession(id); this._updateSessionInAllLists(id, { status: 'stopped', error: null }); }
    catch (err) { this.error = err.message; throw err; }
  },

  async startSession(id, prompt = undefined, model = undefined) {
    this.error = null;
    try {
      const result = await api.startSession(id, prompt, model);
      this._updateSessionInAllLists(id, { status: 'starting' });
      return result;
    } catch (err) { this.error = err.message; throw err; }
  },

  async deleteSession(id) {
    this.error = null;
    try {
      await api.deleteSession(id);
      this.sessions = this.sessions.filter((s) => s.id !== id);
      this.archivedSessions = this.archivedSessions.filter((s) => s.id !== id);
      if (this.currentSession?.id === id) this.currentSession = null;
    } catch (err) { this.error = err.message; throw err; }
  },

  async archiveSession(id) {
    this.error = null;
    try {
      const updated = await api.archiveSession(id);
      this.sessions = this.sessions.filter((s) => s.id !== id);
      this.archivedSessions.unshift(updated);
      this.activeSessions = this.activeSessions.filter((s) => s.id !== id);
      if (this.currentSession?.id === id) this.currentSession = { ...this.currentSession, archived: true };
      return updated;
    } catch (err) { this.error = err.message; throw err; }
  },

  async unarchiveSession(id) {
    this.error = null;
    try {
      const updated = await api.unarchiveSession(id);
      this.archivedSessions = this.archivedSessions.filter((s) => s.id !== id);
      this.sessions.unshift(updated);
      if (this.currentSession?.id === id) this.currentSession = { ...this.currentSession, archived: false };
      return updated;
    } catch (err) { this.error = err.message; throw err; }
  },

  async duplicateSession(id, options = {}) {
    this.error = null;
    try { return await api.duplicateSession(id, options); }
    catch (err) { this.error = err.message; throw err; }
  },

  async toggleSessionStar(sessionId) {
    this.error = null;
    try {
      const updated = await api.toggleSessionStar(sessionId);
      this._updateSessionInAllLists(sessionId, { starred: updated.starred });
      return updated;
    } catch (err) { this.error = err.message; throw err; }
  },

  updateSessionStatus(sessionId, status) {
    const session = this.sessions.find(s => s.id === sessionId) || this.currentSession;
    const wasRunning = session?.status === 'running';
    const updates = { status };
    if (wasRunning && (status === 'waiting' || status === 'completed')) updates.hasResponses = true;
    this._updateSessionInAllLists(sessionId, updates);
  },

  async updateSessionThinking(sessionId, thinkingEnabled) {
    return this.updateSessionFields(sessionId, { thinkingEnabled });
  },

  async updateSessionMode(sessionId, mode) {
    return this.updateSessionFields(sessionId, { mode });
  },

  async updateSessionModel(sessionId, model, providerId = undefined) {
    this.error = null;
    try {
      const updateData = { model };
      if (providerId !== undefined) updateData.providerId = providerId;

      // For draft sessions, also update pendingModel so the backend
      // fallback chain in draftSessionService.startDraft() stays in sync
      const session = this.sessions.find(s => s.id === sessionId)
        || (this.currentSession?.id === sessionId ? this.currentSession : null);
      if (session && session.status === 'waiting') {
        updateData.pendingModel = model;
      }

      const updated = await api.updateSession(sessionId, updateData);
      this._updateSessionInAllLists(sessionId, updateData);
      return updated;
    } catch (err) { this.error = err.message; throw err; }
  },

  async updateNextTemplate(sessionId, nextTemplateId) {
    return this.updateSessionFields(sessionId, { nextTemplateId });
  },

  async updateAutoSendPendingPrompt(sessionId, autoSendPendingPrompt) {
    return this.updateSessionFields(sessionId, { autoSendPendingPrompt });
  },

  async updateSessionFields(sessionId, updates) {
    this.error = null;
    try {
      const updated = await api.updateSession(sessionId, updates);
      this._updateSessionInAllLists(sessionId, updates);
      return updated;
    } catch (err) { this.error = err.message; throw err; }
  },

  updateSession(sessionData) {
    if (!sessionData?.id) return;

    // Handle archive state changes
    if (sessionData.archived === true) {
      this.sessions = moveSessionBetweenLists(this.sessions, this.archivedSessions, sessionData);
      this.activeSessions = this.activeSessions.filter((s) => s.id !== sessionData.id);
    } else if (sessionData.archived === false) {
      this.archivedSessions = moveSessionBetweenLists(this.archivedSessions, this.sessions, sessionData);
    } else {
      // Regular update - update in both lists
      updateSessionInList(this.sessions, sessionData);
      updateSessionInList(this.archivedSessions, sessionData);
    }

    // Update current session and active sessions
    if (this.currentSession?.id === sessionData.id) {
      this.currentSession = { ...this.currentSession, ...sessionData };
    }
    updateSessionInList(this.activeSessions, sessionData);

    // Handle scheduled sessions
    if (sessionData.status === 'scheduled') {
      updateSessionInList(this.scheduledSessions, sessionData, true);
      this.scheduledSessions.sort((a, b) => new Date(a.scheduledAt) - new Date(b.scheduledAt));
    } else {
      this.scheduledSessions = this.scheduledSessions.filter((s) => s.id !== sessionData.id);
    }
  },

  addSessionToList(session) {
    if (!session?.id) return;
    if (!this.sessions.some((s) => s.id === session.id)) this.sessions.unshift(session);
    if (['running', 'waiting', 'starting'].includes(session.status)) {
      if (!this.activeSessions.some((s) => s.id === session.id)) this.activeSessions.unshift(session);
    }
  },

  removeSessionFromList(sessionId) {
    if (!sessionId) return;
    this.sessions = this.sessions.filter((s) => s.id !== sessionId);
    this.archivedSessions = this.archivedSessions.filter((s) => s.id !== sessionId);
    this.activeSessions = this.activeSessions.filter((s) => s.id !== sessionId);
    if (this.currentSession?.id === sessionId) this.currentSession = null;
  },
};

/**
 * Parse git unified diff format into structured data for rendering
 */

/**
 * @typedef {Object} DiffLine
 * @property {'addition'|'deletion'|'context'|'hunk-header'} type
 * @property {string} content - The line content (without +/- prefix)
 * @property {number|null} oldLineNumber
 * @property {number|null} newLineNumber
 */

/**
 * @typedef {Object} DiffHunk
 * @property {string} header - The @@ header line
 * @property {number} oldStart
 * @property {number} oldCount
 * @property {number} newStart
 * @property {number} newCount
 * @property {DiffLine[]} lines
 */

/**
 * @typedef {Object} DiffFile
 * @property {string} oldPath
 * @property {string} newPath
 * @property {string} displayPath - The path to display (usually newPath or oldPath if deleted)
 * @property {boolean} isNew
 * @property {boolean} isDeleted
 * @property {boolean} isRenamed
 * @property {boolean} isBinary - True if git reported this as a binary file
 * @property {DiffHunk[]} hunks
 * @property {number} additions
 * @property {number} deletions
 */

/**
 * Create a new DiffFile object from a "diff --git" line
 * @param {string} line - The diff --git line
 * @returns {DiffFile}
 */
function createFileEntry(line) {
  const match = line.match(/diff --git a\/(.+) b\/(.+)/);
  return {
    oldPath: match ? match[1] : '',
    newPath: match ? match[2] : '',
    displayPath: match ? match[2] : '',
    isNew: false,
    isDeleted: false,
    isRenamed: false,
    isBinary: false,
    hunks: [],
    additions: 0,
    deletions: 0,
  };
}

/**
 * Apply file-level metadata from a header line to the current file.
 * Returns true if the line was consumed as a file header, false otherwise.
 * @param {string} line
 * @param {DiffFile} fileInput
 * @returns {boolean}
 */
function parseFileHeader(line, fileInput) {
  const file = fileInput;
  if (line.startsWith('new file mode')) {
    file.isNew = true;
    return true;
  }
  if (line.startsWith('deleted file mode')) {
    file.isDeleted = true;
    file.displayPath = file.oldPath;
    return true;
  }
  if (line.startsWith('rename from') || line.startsWith('rename to')) {
    file.isRenamed = true;
    return true;
  }
  if (line.startsWith('Binary files')) {
    file.isBinary = true;
    return true;
  }
  if (
    line.startsWith('index ') ||
    line.startsWith('--- ') ||
    line.startsWith('+++ ')
  ) {
    return true;
  }
  return false;
}

/**
 * Parse a hunk header line (@@ ... @@) into a DiffHunk object.
 * Returns the parsed hunk and initial line numbers, or null if the line doesn't match.
 * @param {string} line
 * @returns {{ hunk: DiffHunk, oldLineNum: number, newLineNum: number } | null}
 */
function parseHunkHeader(line) {
  const match = line.match(/@@ -(\d+)(?:,(\d+))? \+(\d+)(?:,(\d+))? @@(.*)?/);
  if (!match) return null;

  const oldLineNum = parseInt(match[1], 10);
  const newLineNum = parseInt(match[3], 10);
  return {
    hunk: {
      header: line,
      oldStart: oldLineNum,
      oldCount: match[2] ? parseInt(match[2], 10) : 1,
      newStart: newLineNum,
      newCount: match[4] ? parseInt(match[4], 10) : 1,
      lines: [],
    },
    oldLineNum,
    newLineNum,
  };
}

/**
 * Classify a single diff content line as addition, deletion, or context.
 * Returns a partial line object with type and content, or null for lines to skip
 * (e.g. "\ No newline at end of file").
 * @param {string} line
 * @returns {{ type: 'addition'|'deletion'|'context', content: string } | null}
 */
function parseLineChange(line) {
  if (line.startsWith('+')) {
    return { type: 'addition', content: line.slice(1) };
  }
  if (line.startsWith('-')) {
    return { type: 'deletion', content: line.slice(1) };
  }
  if (line.startsWith(' ') || line === '') {
    return { type: 'context', content: line.startsWith(' ') ? line.slice(1) : line };
  }
  return null;
}

/**
 * Finalize a file entry by pushing the last hunk (if any) and adding it to the files array.
 * @param {DiffFile} file
 * @param {DiffHunk|null} hunk
 * @param {DiffFile[]} files
 */
function finalizeFile(file, hunk, files) {
  if (hunk) {
    file.hunks.push(hunk);
  }
  files.push(file);
}

/**
 * Add a parsed content line to the current hunk and update line numbers/counts.
 * @param {{ type: 'addition'|'deletion'|'context', content: string }} change
 * @param {DiffHunk} hunk
 * @param {DiffFile} fileInput
 * @param {{ oldLineNum: number, newLineNum: number }} lineNumsInput - Mutated in place
 */
function addLineToHunk(change, hunk, fileInput, lineNumsInput) {
  const file = fileInput;
  const lineNums = lineNumsInput;
  if (change.type === 'addition') {
    hunk.lines.push({ ...change, oldLineNumber: null, newLineNumber: lineNums.newLineNum++ });
    file.additions++;
  } else if (change.type === 'deletion') {
    hunk.lines.push({ ...change, oldLineNumber: lineNums.oldLineNum++, newLineNumber: null });
    file.deletions++;
  } else {
    hunk.lines.push({ ...change, oldLineNumber: lineNums.oldLineNum++, newLineNumber: lineNums.newLineNum++ });
  }
}

/**
 * Parse a unified diff string into structured file objects
 * @param {string} diffText - Raw git diff output
 * @returns {DiffFile[]}
 */
export function parseDiff(diffText) {
  if (!diffText || !diffText.trim()) {
    return [];
  }

  const files = [];
  const lines = diffText.split('\n');
  let currentFile = null;
  let currentHunk = null;
  const lineNums = { oldLineNum: 0, newLineNum: 0 };

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    // File header: diff --git a/path b/path
    if (line.startsWith('diff --git')) {
      if (currentFile) finalizeFile(currentFile, currentHunk, files);
      currentFile = createFileEntry(line);
      currentHunk = null;
      continue;
    }

    if (!currentFile) continue;
    if (parseFileHeader(line, currentFile)) continue;

    // Hunk header: @@ -oldStart,oldCount +newStart,newCount @@ optional context
    if (line.startsWith('@@')) {
      if (currentHunk) currentFile.hunks.push(currentHunk);
      const parsed = parseHunkHeader(line);
      if (parsed) {
        currentHunk = parsed.hunk;
        lineNums.oldLineNum = parsed.oldLineNum;
        lineNums.newLineNum = parsed.newLineNum;
      }
      continue;
    }

    if (!currentHunk) continue;
    const change = parseLineChange(line);
    if (change) addLineToHunk(change, currentHunk, currentFile, lineNums);
  }

  if (currentFile) finalizeFile(currentFile, currentHunk, files);
  return files;
}

/**
 * Get a summary of changes for a diff
 * @param {DiffFile[]} files
 * @returns {{ filesChanged: number, additions: number, deletions: number }}
 */
export function getDiffSummary(files) {
  return files.reduce(
    (acc, file) => ({
      filesChanged: acc.filesChanged + 1,
      additions: acc.additions + file.additions,
      deletions: acc.deletions + file.deletions,
    }),
    { filesChanged: 0, additions: 0, deletions: 0 }
  );
}

